import { useGLTF } from '@react-three/drei';
import { useFrame } from '@react-three/fiber';
import { useRef, useMemo, useLayoutEffect } from 'react';
import * as THREE from 'three';
import { useWorld } from '../Logic/GameWorldContext';
import { MAX_COINS } from '../Logic/constants';
import { sharedAtlasMaterial } from './sharedMaterial';

const temp = new THREE.Object3D();


// ─── Партикл ──────────────────────────────────────────────────────────────────
const sparkGeometry = new THREE.OctahedronGeometry(0.065, 0);
const sparkMat      = new THREE.MeshBasicMaterial({ color: '#fffc66' });

// ─── Константы ────────────────────────────────────────────────────────────────
const IDLE_PER_COIN  = 4;
const BURST_COUNT    = 12;
const MAX_BURSTS     = 8;
const MAX_SPARKS     = MAX_COINS * IDLE_PER_COIN + MAX_BURSTS * BURST_COUNT;
const COLLECT_ANIM   = 0.35;
const BURST_LIFETIME = 0.6;

const burstPool = Array.from({ length: MAX_BURSTS }, () => ({
    active: false, x: 0, y: 0, z: 0, startTime: 0,
    dirs: Array.from({ length: BURST_COUNT }, () => ({ vx: 0, vz: 0 })),
}));

const activateBurst = (x, y, z, time) => {
    const slot = burstPool.find(b => !b.active) ?? burstPool[0];
    slot.active = true; slot.x = x; slot.y = y; slot.z = z; slot.startTime = time;
    for (let i = 0; i < BURST_COUNT; i++) {
        const angle = (i / BURST_COUNT) * Math.PI * 2 + (Math.random() - 0.5) * 0.4;
        const radius = 1.5 + Math.random() * 1.5;
        slot.dirs[i].vx = Math.cos(angle) * radius;
        slot.dirs[i].vz = Math.sin(angle) * radius;
    }
};

export default function CoinView() {
    const { nodes } = useGLTF('/models/coin.glb');

    const goldGeometry = useMemo(() => nodes.coin_gold?.geometry ?? null, [nodes]);
    const redGeometry  = useMemo(() => nodes.coin_red?.geometry  ?? null, [nodes]);

    const goldRef    = useRef();
    const redRef     = useRef();
    const sparkRef   = useRef();
    const world      = useWorld();

    // Сбрасываем count=0 при маунте — нет чёрных монет на origin
    useLayoutEffect(() => {
        [goldRef, redRef, sparkRef].forEach(r => {
            if (r.current) r.current.count = 0;
        });
    }, [goldGeometry, redGeometry]);

    useFrame((state) => {
        if (!goldGeometry || !redGeometry) return;
        const time  = state.clock.elapsedTime;
        const coins = world.coins;
        const sparkMesh = sparkRef.current;

        let goldIdx = 0, redIdx = 0, sparkIdx = 0;

        for (let i = 0; i < coins.length; i++) {
            const c = coins[i];

            if (c.collected) {
                if (c.collectTime === undefined) {
                    c.collectTime = time;
                    activateBurst(c.x, c.floatY ?? 0.65, c.z, time);
                }
                const t = (time - c.collectTime) / COLLECT_ANIM;
                if (t >= 1) continue;
                const flyY  = (c.floatY ?? 0.65) + t * 1.2;
                const scale = Math.max(0, 1 + t * 0.8 - t * t * 1.6);
                temp.position.set(c.x, flyY, c.z);
                temp.rotation.set(0, c.spinY ?? 0, 0);
                temp.scale.setScalar(scale);
                temp.updateMatrix();
            } else {
                const floatY = 0.65 + Math.sin(time * 2.2 + c.phase) * 0.12;
                const spinY  = time * 2.8 + c.phase;
                c.floatY = floatY; c.spinY = spinY;
                temp.position.set(c.x, floatY, c.z);
                temp.rotation.set(0, spinY, 0);
                temp.scale.setScalar(1);
                temp.updateMatrix();
                // Записываем матрицу монеты ДО изменения temp искрами
                if (c.type === 'gold') goldRef.current?.setMatrixAt(goldIdx++, temp.matrix);
                else                   redRef.current?.setMatrixAt(redIdx++, temp.matrix);
                // Idle sparks — inline, floatY уже вычислен
                if (sparkMesh) {
                    for (let j = 0; j < IDLE_PER_COIN; j++) {
                        const phase  = c.phase + j * (Math.PI * 2 / IDLE_PER_COIN);
                        const radius = 0.45 + Math.sin(time * 1.8 + phase * 1.3) * 0.1;
                        temp.position.set(c.x + Math.cos(time * 1.4 + phase) * radius, floatY + Math.sin(time * 2.5 + phase * 2) * 0.12, c.z + Math.sin(time * 1.4 + phase) * radius);
                        temp.rotation.set(time + phase, time * 0.7, 0);
                        temp.scale.setScalar(0.4 + Math.abs(Math.sin(time * 3.0 + phase)) * 0.6);
                        temp.updateMatrix();
                        sparkMesh.setMatrixAt(sparkIdx++, temp.matrix);
                    }
                }
                continue; // setMatrixAt уже вызван выше
            }

            if (c.type === 'gold') goldRef.current?.setMatrixAt(goldIdx++, temp.matrix);
            else                   redRef.current?.setMatrixAt(redIdx++, temp.matrix);
        }

        if (goldRef.current) { goldRef.current.count = goldIdx; goldRef.current.instanceMatrix.needsUpdate = true; }
        if (redRef.current)  { redRef.current.count  = redIdx;  redRef.current.instanceMatrix.needsUpdate  = true; }

        if (!sparkMesh) return;

        for (let b = 0; b < MAX_BURSTS; b++) {
            const burst = burstPool[b];
            if (!burst.active) continue;
            const age = time - burst.startTime;
            if (age >= BURST_LIFETIME) { burst.active = false; continue; }
            const t = age / BURST_LIFETIME;
            const spread = 1 - (1-t)*(1-t)*(1-t);
            const scale = (1 - t) * 2.0;
            if (scale <= 0.01) continue;
            for (let j = 0; j < BURST_COUNT; j++) {
                const d = burst.dirs[j];
                temp.position.set(burst.x + d.vx * spread, burst.y, burst.z + d.vz * spread);
                temp.rotation.set(age * 4 + j, age * 2, 0);
                temp.scale.setScalar(scale);
                temp.updateMatrix();
                sparkMesh.setMatrixAt(sparkIdx++, temp.matrix);
            }
        }

        sparkMesh.count = sparkIdx;
        sparkMesh.instanceMatrix.needsUpdate = true;
    });

    if (!goldGeometry || !redGeometry) return null;

    return (
        <group>
            <instancedMesh ref={goldRef}  args={[goldGeometry, sharedAtlasMaterial, MAX_COINS]} castShadow frustumCulled={false} />
            <instancedMesh ref={redRef}   args={[redGeometry,  sharedAtlasMaterial, MAX_COINS]} castShadow frustumCulled={false} />
            <instancedMesh ref={sparkRef} args={[sparkGeometry, sparkMat,    MAX_SPARKS]} frustumCulled={false} />
        </group>
    );
}

useGLTF.preload('/models/coin.glb');