import { useGameStore } from '../Logic/store';
import ShopModal from './ShopModal';
import Chest from './Chest';

export default function ChestMenu() {
    const isChestOpen  = useGameStore(s => s.isChestOpen);
    const closeChest   = useGameStore(s => s.closeChest);    // ← назад в меню
    const closeChestAll = useGameStore(s => s.closeChestAll); // ✕ всё закрыть

    if (!isChestOpen) return null;

    return (
        <ShopModal
            title="SHOP"
            onBack={closeChest}
            onClose={closeChestAll}
            width="400px"
            height="600px"
        >
            <Chest />
        </ShopModal>
    );
}
