import { ContactShadows } from '@react-three/drei';
import { useFrame } from '@react-three/fiber';
import { useRef } from 'react';
import { useGameStore } from '../Logic/store';
import { useWorld } from '../Logic/GameWorldContext';
import { SHADOW_QUALITY_MEDIUM } from '../Logic/constants';

export default function ContactShadowLayer() {
    const shadowQuality = useGameStore(s => s.shadowQuality);
    const world         = useWorld();
    const groupRef      = useRef();

    useFrame(() => {
        const player = world.playerRef?.current;
        if (!groupRef.current || !player) return;
        groupRef.current.position.z = player.position.z;
    });

    if (shadowQuality !== SHADOW_QUALITY_MEDIUM) return null;

    return (
        <group ref={groupRef}>
            <ContactShadows
                position={[0, 0.02, 0]}
                opacity={0.55}
                scale={28}
                blur={1.8}
                far={4}
                resolution={256}
                color="#000000"
            />
        </group>
    );
}
