import * as THREE from 'three';

// Общий GLSL-блок деформации — вставляется в оба материала
const DEFORM_DECLARATIONS = `
uniform float uStretch;
uniform float uTwist;
uniform float uBend;`;

const DEFORM_CODE = `
// ── STRETCH (volume-preserving) ──────────────────────────────
transformed.y *= uStretch;
float _inv = 1.0 / sqrt(max(abs(uStretch), 0.01));
transformed.xz *= _inv;

// ── TWIST вокруг Y (нарастает с высотой) ─────────────────────
float _ta = transformed.y * uTwist;
float _ts = sin(_ta);
float _tc = cos(_ta);
transformed.xz = mat2(_tc, -_ts, _ts, _tc) * transformed.xz;

// ── BEND вперёд (квадратичная кривая по Z) ───────────────────
float _b = transformed.y * uBend;
transformed.z += _b * abs(_b);`;

function injectDeform(shader, uniforms) {
    shader.uniforms.uStretch      = uniforms.uStretch;
    shader.uniforms.uTwist        = uniforms.uTwist;
    shader.uniforms.uBend         = uniforms.uBend;
    shader.uniforms.uShadowFactor = uniforms.uShadowFactor;
    shader.vertexShader = shader.vertexShader
        .replace('#include <common>',      `#include <common>${DEFORM_DECLARATIONS}`)
        .replace('#include <begin_vertex>', `#include <begin_vertex>${DEFORM_CODE}`);
    shader.fragmentShader = shader.fragmentShader
        .replace('#include <common>', `#include <common>\nuniform float uShadowFactor;`)
        .replace('#include <dithering_fragment>',
            `gl_FragColor.rgb *= mix(1.0, 0.65, uShadowFactor);\n#include <dithering_fragment>`);
}

/**
 * Создаёт основной материал курицы (vertexColors) + uniforms-объект.
 * Возвращает { mat, uniforms }.
 */
export function createChickenDeformMaterial() {
    const uniforms = {
        uStretch:      { value: 1.0 },
        uTwist:        { value: 0.0 },
        uBend:         { value: 0.0 },
        uShadowFactor: { value: 0.0 },
    };

    const mat = new THREE.MeshStandardMaterial({ vertexColors: true, flatShading: false });
    mat.color.setScalar(1.8);
    mat.onBeforeCompile = (shader) => injectDeform(shader, uniforms);
    mat.customProgramCacheKey = () => 'chicken_deform_v2';

    return { mat, uniforms };
}

/**
 * Создаёт материал для экипированных предметов, разделяющий те же uniforms что
 * и курица — все GSAP-анимации (stretch/twist/bend) автоматически применяются к обоим.
 *
 * @param {string|number} color    - CSS-цвет или hex (напр. '#ff0000' или 0xff0000)
 * @param {object}        uniforms - ссылка на world.deformUniforms курицы (НЕ копия!)
 * @param {object}        opts     - доп. параметры MeshStandardMaterial
 */
export function createItemDeformMaterial(color, uniforms, opts = {}) {
    const mat = new THREE.MeshStandardMaterial({
        color,
        roughness: 0.45,
        metalness: 0.25,
        ...opts,
    });
    // Каждый material получает УНИКАЛЬНЫЙ ключ чтобы Three.js не делил шейдерный кэш
    const colorKey = typeof color === 'string' ? color : color.toString(16);
    mat.onBeforeCompile = (shader) => injectDeform(shader, uniforms);
    mat.customProgramCacheKey = () => `item_deform_${colorKey}`;
    return mat;
}
