import { useFrame } from "@react-three/fiber";
import gsap from "gsap";
import { useEffect, useRef, useMemo } from "react";
import * as THREE from 'three';
import Explosion from "../Effects/Explosion";
import ExplosionC4 from "../Effects/ExplosionC4";
import VoxelFire from "../Effects/VoxelFire";
import Feathers from "../Effects/Feathers";
import { Physics } from "../Logic/PhysicsEngine";
import { useGameStore } from "../Logic/store";
import Chicken from "./Chicken";
import Roasted from "./Roasted";
import EquippedItems from "./EquippedItems";
import { SoundManager } from "../Effects/SoundManager";
import { useWorld } from "../Logic/GameWorldContext";
import { createChickenDeformMaterial } from "./chickenDeformMaterial";

export default function Player() {
    const meshRef = useRef();
    const world   = useWorld();

    const isDead              = useGameStore(s => s.isDead);
    const deathType           = useGameStore(s => s.deathType);
    const invulnerabilityActive = useGameStore(s => s.invulnerabilityActive);
    const explosionPos  = useGameStore(s => s.explosionPos);
    const isMoving      = useGameStore(s => s.isMoving);
    const restartTrigger = useGameStore(s => s.restartTrigger);
    const equippedItems  = useGameStore(s => s.equippedItems);
    const chickenColorIdx = useGameStore(s => s.chickenColorIdx);

    // ── Deform material — один инстанс на всё время жизни компонента ───────────
    const { mat: deformMat, uniforms: deformUniforms } = useMemo(
        () => createChickenDeformMaterial(), []
    );

    // Кладём uniforms в world, чтобы PlayerController мог анимировать их напрямую
    useEffect(() => {
        world.deformUniforms = deformUniforms;
        return () => { world.deformUniforms = null; };
    }, []);

    // ── Idle анимация через uTwist (взгляд влево/вправо) и uBend (клевок) ──────
    const idleTimer  = useRef(null);
    const idleTween  = useRef(null);
    const isIdling   = useRef(false);

    const startIdle = () => {
        if (isIdling.current) return;
        isIdling.current = true;
        SoundManager.play('chickenIdle', false);
        const u = deformUniforms;

        idleTween.current = gsap.timeline({ repeat: -1, repeatDelay: 0.5 })
            // Клевок 1 — uBend вперёд
            .to(u.uBend, { value:  0.55, duration: 0.11, ease: 'power2.in'  })
            .to(u.uBend, { value: -0.12, duration: 0.16, ease: 'power2.out' })
            .to(u.uBend, { value:  0,    duration: 0.10 })
            .to({}, { duration: 0.4 })
            // Клевок 2 (короче)
            .to(u.uBend, { value:  0.42, duration: 0.09, ease: 'power2.in'  })
            .to(u.uBend, { value: -0.09, duration: 0.13, ease: 'power2.out' })
            .to(u.uBend, { value:  0,    duration: 0.09 })
            .to({}, { duration: 0.3 })
            // Twist влево — верхняя часть тела крутится, как будто смотрит в сторону
            .to(u.uTwist, { value:  0.55, duration: 0.22, ease: 'sine.inOut' })
            .to({}, { duration: 0.28 })
            .to(u.uTwist, { value:  0,    duration: 0.18, ease: 'sine.inOut' })
            .to({}, { duration: 0.2 })
            // Twist вправо
            .to(u.uTwist, { value: -0.55, duration: 0.20, ease: 'sine.inOut' })
            .to({}, { duration: 0.28 })
            .to(u.uTwist, { value:  0,    duration: 0.18, ease: 'sine.inOut' });
    };

    const stopIdle = () => {
        if (!isIdling.current) return;
        isIdling.current = false;
        if (idleTween.current) { idleTween.current.kill(); idleTween.current = null; }
        // Плавный возврат деформаций в ноль
        gsap.to(deformUniforms.uBend,  { value: 0, duration: 0.12 });
        gsap.to(deformUniforms.uTwist, { value: 0, duration: 0.12 });
        if (idleTimer.current) { clearTimeout(idleTimer.current); idleTimer.current = null; }
    };

    useEffect(() => {
        if (isDead) { stopIdle(); return; }
        if (isMoving) {
            stopIdle();
        } else {
            idleTimer.current = setTimeout(startIdle, 5000);
        }
        return () => { if (idleTimer.current) clearTimeout(idleTimer.current); };
    }, [isMoving, isDead]);

    useEffect(() => {
        if (invulnerabilityActive) SoundManager.play('chickenPanic', false);
    }, [invulnerabilityActive]);

    useEffect(() => {
        world.playerRef = meshRef;
        return () => { world.playerRef = null; };
    }, []);

    useFrame((_) => {
        const player = meshRef.current;
        if (isDead || !player) return;

        // ── Затемнение курицы от пропса в z-1, x-1 ───────────────────────────
        const px = player.position.x, pz = player.position.z;
        const rz = Math.round(pz) - 1;
        let minDist = Infinity;
        for (const p of world.props) {
            if (Math.round(p.z) === rz) minDist = Math.min(minDist, Math.abs(px - (p.x - 1)));
        }
        const target = minDist < 1.5 ? 1 - minDist / 1.5 : 0;
        deformUniforms.uShadowFactor.value = THREE.MathUtils.lerp(
            deformUniforms.uShadowFactor.value, target, 0.12
        );

        const currentLog  = Physics.getLogUnderPlayer(world);
        const currentLily = Physics.getLilyUnderPlayer(world);

        if (currentLog && !isMoving) {
            player.position.x += currentLog.lastMove;
            currentLog.yOffset = THREE.MathUtils.lerp(currentLog.yOffset || 0, -0.12, 0.1);
            const inv = currentLog.direction > 0 ? 1 : -1;
            const targetRotX = (player.position.z - currentLog.z) * 0.2 * inv;
            const targetRotZ = (currentLog.x - player.position.x) * 0.1;
            currentLog.rotX = THREE.MathUtils.lerp(currentLog.rotX || 0, targetRotX, 0.1);
            currentLog.rotZ = THREE.MathUtils.lerp(currentLog.rotZ || 0, targetRotZ, 0.1);
        }

        if (currentLily && !isMoving) {
            currentLily.yOffset = THREE.MathUtils.lerp(currentLily.yOffset || 0, -0.1, 0.2);
        }
    });

    useEffect(() => {
        stopIdle();
        gsap.killTweensOf(meshRef.current.position);
        gsap.killTweensOf(meshRef.current.scale);
        gsap.killTweensOf(meshRef.current.rotation);
        gsap.killTweensOf(deformUniforms.uStretch);
        gsap.killTweensOf(deformUniforms.uTwist);
        gsap.killTweensOf(deformUniforms.uBend);
        deformUniforms.uStretch.value = 1.0;
        deformUniforms.uTwist.value   = 0.0;
        deformUniforms.uBend.value    = 0.0;
        if (meshRef.current) {
            meshRef.current.position.set(0, 0, 0);
            meshRef.current.rotation.set(0, 0, 0);
            meshRef.current.scale.set(1, 1, 1);
            meshRef.current.visible = true;
        }
        world.playerRef = meshRef;
    }, [restartTrigger]);

    useEffect(() => {
        if (isDead && meshRef.current) {
            const mesh = meshRef.current;
            SoundManager.play(deathType === 'Sniper' ? 'deathSniper' : 'death');
            if (deathType === 'HE')      SoundManager.play('grenadeExplosion', false);
            if (deathType === 'Molotov') SoundManager.play('molotov');

            if (deathType === "HE" || deathType === "C4" || deathType === "Molotov") {
                const u = deformUniforms;
                const tl = gsap.timeline();

                // 1. Подброс вверх — резкий stretch
                tl.to(mesh.position, {
                    y: 2.2, z: mesh.position.z - 0.4,
                    duration: 0.38, ease: "power3.out"
                }, 0);
                tl.to(u.uStretch, { value: 1.7,  duration: 0.25, ease: "power2.out" }, 0);
                tl.to(u.uTwist,   { value: Math.PI * 0.6, duration: 0.42, ease: "sine.inOut" }, 0);

                // 2. Пик — небольшое зависание + squash на вершине
                tl.to(mesh.position, { y: 2.4, duration: 0.12, ease: "power1.out" }, 0.36);
                tl.to(u.uStretch, { value: 0.75, duration: 0.12, ease: "power2.in" }, 0.36);

                // 3. Падение вниз — stretch нарастает по мере ускорения
                tl.to(mesh.position, { y: 0.0, duration: 0.44, ease: "power2.in"  }, 0.48);
                tl.to(u.uStretch,    { value: 1.65, duration: 0.38, ease: "power2.in" }, 0.48);

                // 4. Squash при ударе о землю — резкий сплюск
                tl.to(u.uStretch, { value: 0.22, duration: 0.08, ease: "power4.in"  }, 0.88);

                // 5. Bounce: вытягивается → чуть сплющивается → норма
                tl.to(u.uStretch, { value: 1.35, duration: 0.12, ease: "power2.out" }, 0.96);
                tl.to(u.uStretch, { value: 0.82, duration: 0.09, ease: "power2.in"  }, 1.08);
                tl.to(u.uStretch, { value: 1.0,  duration: 0.50, ease: "elastic.out(1, 0.4)" }, 1.17);

                // 6. Twist медленно гасится
                tl.to(u.uTwist, { value: 0, duration: 1.0, ease: "elastic.out(1, 0.35)" }, 1.0);

                // 7. Плавный завал на бок
                tl.to(mesh.rotation, { z: Math.PI * 0.5, duration: 0.9, ease: "power2.inOut" }, 1.5);
                tl.to(mesh.position, { y: -0.05, duration: 0.25, ease: "power2.in" }, 2.2);
            }

            if (deathType === "Drown") {
                SoundManager.play('drown');
                const u = deformUniforms;
                const tl = gsap.timeline();

                // Небольшой испуганный подскок
                tl.to(mesh.position, { y: 0.5, duration: 0.12, ease: "power2.out" }, 0);
                tl.to(u.uStretch,    { value: 1.5,  duration: 0.10, ease: "power2.out" }, 0);

                // Squash при падении на воду
                tl.to(mesh.position, { y: 0, duration: 0.10, ease: "power2.in" }, 0.12);
                tl.to(u.uStretch,    { value: 0.45, duration: 0.09, ease: "power3.in"  }, 0.22);
                tl.to(u.uStretch,    { value: 0.9,  duration: 0.08, ease: "power2.out" }, 0.31);

                // Медленное утопание
                tl.to(mesh.position, { y: -1.4, duration: 1.1, ease: "power2.in" }, 0.38);
                tl.to(u.uStretch,    { value: 0.08, duration: 1.1, ease: "power2.in" }, 0.38);
                tl.to(mesh.scale,    { x: 0.6, y: 1, z: 0.6, duration: 1.1, ease: "power2.in" }, 0.38);
            }

            if (deathType === "Sniper") {
                mesh.visible = false;
            }
        }
    }, [isDead, deathType]);

    const isRoasted = isDead && (deathType === 'HE' || deathType === 'C4' || deathType === 'Molotov');

    return (
        <>
            <group ref={ meshRef }>
                <Chicken
                    visible={ !isRoasted }
                    colorIdx={ chickenColorIdx }
                    material={ deformMat }
                />
                <Roasted visible={ isRoasted } material={ deformMat } />
                { !isRoasted && <EquippedItems equippedItems={ equippedItems } deformUniforms={ deformUniforms } /> }
                { invulnerabilityActive && (
                    <mesh position={[0, 0.45, 0]}>
                        <sphereGeometry args={[0.78, 18, 14]} />
                        <meshStandardMaterial
                            color="#44aaff"
                            transparent
                            opacity={0.18}
                            side={THREE.BackSide}
                            depthWrite={false}
                            roughness={0.2}
                            metalness={0.1}
                        />
                    </mesh>
                )}
            </group>
            { isRoasted && deathType === 'HE'      && <Explosion   position={ [explosionPos[0], 0, explosionPos[2]] } /> }
            { isRoasted && deathType === 'C4'      && <ExplosionC4 position={ [explosionPos[0], 0, explosionPos[2]] } /> }
            { isRoasted && deathType === 'Molotov' && <VoxelFire   position={ [explosionPos[0], 0, explosionPos[2]] } /> }
            { isDead && <Feathers position={ [explosionPos[0], 0, explosionPos[2]] } /> }
        </>
    );
}