import gsap from "gsap";
import { useEffect, useRef } from "react";
import { Physics } from "../Logic/PhysicsEngine";
import { useGameStore } from "../Logic/store";
import { useFrame } from "@react-three/fiber";
import { SoundManager } from "../Effects/SoundManager";
import { emitRipple } from "../View/WaterRowMaterial";
import { useWorld } from "../Logic/GameWorldContext";

export default function PlayerController() {
    const isDead = useGameStore(s => s.isDead);
    const restartTrigger = useGameStore(s => s.restartTrigger);
    const world = useWorld();
    const currentKey = useRef(null);
    const lastClickTime = useRef(0)
    const queue = useRef([]);
    const canMove = useRef(true);

    // 2. ЦИКЛ ОБРАБОТКИ ОЧЕРЕДИ
    useFrame(() => {
        if (!canMove.current || queue.current.length === 0) return;
        const { isDead: dead, isPaused, upgradeMenuOpen, isStarted } = useGameStore.getState();
        if (!dead && !isPaused && !upgradeMenuOpen && isStarted) {
            const nextMove = queue.current.shift();
            handleMove(nextMove.dir);
        }
    });

    const handleMove = (dir) => {
        const { isDead: dead, addScore } = useGameStore.getState();
        const player = world.playerRef?.current;
        if (dead || !canMove.current || !player) return;

        gsap.killTweensOf(player.position);
        gsap.killTweensOf(player.scale);
        // Убиваем предыдущую stretch-анимацию если ещё идёт
        const u = world.deformUniforms;
        if (u) gsap.killTweensOf(u.uStretch);

        player.position.y = 0; // Сбрасываем Y при каждом новом движении, чтобы избежать багов с прыжком

        // 1. РАСЧЕТ ЦЕЛИ (СЕТКА + УМНЫЙ X)
        let dx = 0, dz = 0;
        if (dir === "up") dz = 1;
        else if (dir === "down") dz = -1;
        else if (dir === "left") dx = 1;
        else if (dir === "right") dx = -1;

        // Счётчик шагов назад для снайпера
        if (dir === "down") {
            useGameStore.setState(s => ({ backSteps: s.backSteps + 1, forwardSteps: 0 }));
        } else if (dir === "up") {
            // Только вперёд — не сбрасываем снайпер сразу, лишь считаем шаги
            // DangerController сбросит прицел сам после 5 шагов вперёд
            useGameStore.setState(s => ({ backSteps: 0, forwardSteps: s.forwardSteps + 1 }));
        }

        // 1. ВЫЧИСЛЯЕМ ЦЕЛЕВУЮ КЛЕТКУ (Округляем текущую позицию)
        const curX = player.position.x;
        const curZ = Math.round(player.position.z);
        const nextZ = curZ + dz;
        const rotY = Math.atan2(dx, dz);
        const isWaterMode = world.waters.has(nextZ) || world.waters.has(curZ); // Если мы на воде или прыгаем на воду, используем умный X
        const nextX = isWaterMode ? curX + dx : Math.round(curX) + dx;

        // 2. ПРОВЕРКА ПО СЕТКЕ
        if (Physics.isCellOccupied(world, nextX, nextZ)) {
            // Проигрываем анимацию "упора" (поворот без движения)
            // 1. ВОЗВРАЩАЕМ КУРИЦУ В НОРМАЛЬНУЮ ФОРМУ (отменяем "зарядку")
            // Это тот самый блок из твоего старого кода

            SoundManager.play('hit');
            // Сбрасываем деформацию заряда
            const u = world.deformUniforms;
            if (u) {
                gsap.killTweensOf(u.uStretch);
                gsap.to(u.uStretch, { value: 1.0, duration: 0.2, ease: "back.out(2)" });
            }
            gsap.to(player.scale, { x: 1, y: 1, z: 1, duration: 0.2, ease: "back.out(2)" });
            gsap.to(player.rotation, { y: rotY, duration: 0.1 });
            gsap.to(player.position, {
                x: player.position.x + dx * 0.1,
                z: player.position.z + dz * 0.1,
                duration: 0.05,
                yoyo: true,
                repeat: 1
            });
            // Если уперлись в стену — очищаем очередь, чтобы не "долбиться" в неё
            queue.current = [];
            return;
        }
        // --- 3. ЛОГИКА УСКОРЕНИЯ (ТУРБО) ---
        const now = Date.now();
        const isSpamming = now - lastClickTime.current < 250;
        lastClickTime.current = now;

        // Динамические параметры из твоего старого кода
        const duration = isSpamming ? 0.12 : 0.2;
        const jumpHeight = isSpamming ? 0.6 : 0.9; // При спаме прыгаем ниже для скорости

        // 3. ЗАПУСК СОЧНОГО ПРЫЖКА
        canMove.current = false;
        useGameStore.setState({ isMoving: true });

        // ТРЯСКА ПЛАТФОРМЫ ПРИ ОТТАЛКИВАНИИ
        if (world.waters.has(curZ)) {
            const log  = Physics.getLogUnderPlayer(world);
            const lily = Physics.getLilyUnderPlayer(world);
            // shakeTime = -1 — флаг "начать тряску" для View (View сама запишет реальный time)
            if (log)  { log.shakeTime  = -1; log.shakeDir  = dz; }
            if (lily) { lily.shakeTime = -1; lily.shakeDir = dz; }
            // Рипл и всплеск при отталкивании
            const px = world.playerRef?.current?.position.x ?? 0;
            emitRipple(px, curZ, 'depart');
            world.emitWaterSplash?.(px, curZ);
        } else {
            // Пыль при отталкивании с земли
            const px = world.playerRef?.current?.position.x ?? 0;
            world.emitDustPuff?.(px, curZ);
        }

        const tl = gsap.timeline({
            onStart: () => SoundManager.play('jump'),
            onComplete: () => {
                canMove.current = true;
                useGameStore.setState({ isMoving: false });
                if (dir === "up") addScore(nextZ);
                SoundManager.play('land');
                if (world.waters.has(nextZ)) {
                    SoundManager.play('boat');
                    emitRipple(nextX, nextZ, 'land');
                    world.emitWaterSplash?.(nextX, nextZ);
                    const log  = Physics.getLogUnderPlayer(world);
                    const lily = Physics.getLilyUnderPlayer(world);
                    if (log)  { log.shakeTime  = -1; log.shakeDir  = -dz; }
                    if (lily) { lily.shakeTime = -1; lily.shakeDir = -dz; }
                } else {
                    world.emitDustPuff?.(nextX, nextZ);
                }
                // Упругий отскок формы: squash → stretch → squash → норма
                const u2 = world.deformUniforms;
                if (u2) {
                    gsap.killTweensOf(u2.uStretch);
                    const bounceTl = gsap.timeline();
                    bounceTl
                        // Stretch после squash — умеренный
                        .to(u2.uStretch, { value: 1.15, duration: 0.11, ease: 'power2.out'  })
                        // Ещё раз небольшой сплюск
                        .to(u2.uStretch, { value: 0.90, duration: 0.08, ease: 'power2.in'   })
                        // Возврат в норму
                        .to(u2.uStretch, { value: 1.0,  duration: 0.22, ease: 'elastic.out(1, 0.55)' });
                }
            }
        });

        // Поворот (угол через atan2 как в оригинале)
        const angle = Math.atan2(dx, dz);
        tl.to(player.rotation, { y: angle, duration: 0.1 }, 0);

        // Полет (X, Z)
        tl.to(player.position, {
            x: nextX,
            z: nextZ,
            duration: duration,
            ease: isSpamming ? "power1.inOut" : "sine.inOut"
        }, 0);

        // Подскок (Y)
        tl.to(player.position, {
            y: jumpHeight,
            duration: duration / 2,
            yoyo: true,
            repeat: 1,
            ease: "power2.out"
        }, 0);

        // Squash & Stretch через шейдер
        if (u) {
            gsap.killTweensOf(u.uStretch);
            // Взлёт — плавный stretch
            tl.to(u.uStretch, { value: 1.32, duration: duration * 0.55, ease: "sine.out"   }, 0);
            // Глубокий squash при приземлении (bounce-цикл продолжится в onComplete)
            tl.to(u.uStretch, { value: 0.52, duration: duration * 0.20, ease: "power3.in"  }, duration * 0.80);
        }
    };

    useEffect(() => {
        // Keyboard
        const onKeyDown = (e) => {
            const { isDead: dead, isPaused, isStarted } = useGameStore.getState();
            if (dead || isPaused || !isStarted) return;
            const player = world.playerRef?.current;
            if (!player) return;

            const keys = {
                w: "up", s: "down", a: "left", d: "right",
                ArrowUp: "up", ArrowDown: "down", ArrowLeft: "left", ArrowRight: "right"
            };
            if (keys[e.key] && !currentKey.current) {
                currentKey.current = e.key;
                queue.current = [];

                // Зарядка — squash через шейдер (charge pose)
                const u = world.deformUniforms;
                if (canMove.current && u) {
                    gsap.killTweensOf(u.uStretch);
                    gsap.to(u.uStretch, { value: 0.78, duration: 0.14, ease: "sine.inOut" });
                }
            }
        };
        const onKeyUp = (e) => {
            const { isPaused, isStarted } = useGameStore.getState();
            if (isPaused || !isStarted) return;
            if (e.key === currentKey.current) {
                const keyMap = {
                    w: "up", ArrowUp: "up",
                    s: "down", ArrowDown: "down",
                    a: "left", ArrowLeft: "left",
                    d: "right", ArrowRight: "right"
                };
                const dir = keyMap[e.key];

                if (dir && e.key === currentKey.current) {
                    queue.current.push({ dir });
                    currentKey.current = null;
                }
            }
        };

        // Mobile Touch
        let touchStart = { x: 0, y: 0 };
        const onTouchStart = (e) => {
            const { isDead: dead, isPaused, isStarted } = useGameStore.getState();
            if (dead || isPaused || !isStarted) return;
            const player = world.playerRef?.current;
            if (!player) return;

            touchStart = { x: e.touches[0].clientX, y: e.touches[0].clientY };
            queue.current = [];

            const u = world.deformUniforms;
            if (canMove.current && u) {
                gsap.killTweensOf(u.uStretch);
                gsap.to(u.uStretch, { value: 0.78, duration: 0.14, ease: "sine.inOut" });
            }
        };
        const onTouchEnd = (e) => {
            const { isPaused, isStarted } = useGameStore.getState();
            if (isPaused || !isStarted) return;
            const dx = e.changedTouches[0].clientX - touchStart.x;
            const dy = e.changedTouches[0].clientY - touchStart.y;
            let dir = null;

            if (Math.abs(dx) < 10 && Math.abs(dy) < 10) dir = "up";
            else if (Math.abs(dx) > Math.abs(dy)) dir = dx < 0 ? "left" : "right";
            else dir = dy > 0 ? "down" : "up";

            if (dir) {
                queue.current.push({ dir });
            }
        };

        window.addEventListener("keydown", onKeyDown);
        window.addEventListener("keyup", onKeyUp);
        window.addEventListener("touchstart", onTouchStart);
        window.addEventListener("touchend", onTouchEnd);
        return () => {
            window.removeEventListener("keydown", onKeyDown);
            window.removeEventListener("keyup", onKeyUp);
            window.removeEventListener("touchstart", onTouchStart);
            window.removeEventListener("touchend", onTouchEnd);
        };
    }, []); // eslint-disable-line

    useEffect(() => {
        if (isDead) {
            canMove.current = false;
            if (queue.current) queue.current = [];
            if (world.playerRef?.current) {
                gsap.killTweensOf(world.playerRef.current.position);
                gsap.killTweensOf(world.playerRef.current.scale);
                gsap.killTweensOf(world.playerRef.current.rotation);
            }
            // Убиваем все деформации шейдера
            const u = world.deformUniforms;
            if (u) {
                gsap.killTweensOf(u.uStretch);
                gsap.killTweensOf(u.uTwist);
                gsap.killTweensOf(u.uBend);
            }
        }
    }, [isDead, world]);

    // СБРОС ПРИ РЕСТАРТЕ
    useEffect(() => {
        canMove.current = true;
        queue.current = [];
        currentKey.current = null;
    }, [restartTrigger]); // Магия здесь: сработает при каждом нажатии Restart

    return null;
}