import { useGLTF } from '@react-three/drei';
import { useMemo } from 'react';
import { SLOTS, itemById } from '../Shop/items';
import { createItemDeformMaterial } from './chickenDeformMaterial';

// ─── Предмет из items.glb ─────────────────────────────────────────────────────
function GlbEquippedItem({ item, deformUniforms }) {
    const { nodes } = useGLTF('/models/items.glb');
    const meshNode = nodes[item.modelKey];

    // Если геометрия содержит vertex colors — сохраняем их через vertexColors: true
    const hasVertexColors = !!(meshNode?.geometry?.attributes?.color);

    const deformMat = useMemo(() => {
        if (!deformUniforms) return null;
        if (hasVertexColors) {
            // Белый цвет-множитель + vertexColors — получаем оригинальные цвета из GLB
            return createItemDeformMaterial('#ffffff', deformUniforms, { vertexColors: true });
        }
        const baseColor = meshNode?.material?.color ?? item.color ?? '#ffffff';
        return createItemDeformMaterial(baseColor, deformUniforms);
    }, [deformUniforms, hasVertexColors, item.color]);

    if (!meshNode) return null;

    return (
        <mesh
            geometry={meshNode.geometry}
            material={deformMat ?? meshNode.material}
            position={item.pos}
            rotation={item.rot}
            scale={item.scale || [1, 1, 1]}
            castShadow
        />
    );
}

// ─── Процедурный предмет (box / sphere / cone / torus) ───────────────────────
function ProceduralEquippedItem({ item, deformUniforms }) {
    const deformMat = useMemo(() => {
        if (!deformUniforms) return null;
        return createItemDeformMaterial(item.color, deformUniforms);
    }, [deformUniforms, item.color]);

    let geo = null;
    if (item.type === 'box')    geo = <boxGeometry    args={item.geo} />;
    if (item.type === 'sphere') geo = <sphereGeometry args={item.geo} />;
    if (item.type === 'cone')   geo = <coneGeometry   args={item.geo} />;
    if (item.type === 'torus')  geo = <torusGeometry  args={item.geo} />;
    if (!geo) return null;

    return (
        <mesh position={item.pos} rotation={item.rot} castShadow>
            {geo}
            {deformMat
                ? <primitive object={deformMat} attach="material" />
                : <meshStandardMaterial color={item.color} roughness={0.45} metalness={0.25} />
            }
        </mesh>
    );
}

// ─── Роутер по типу ──────────────────────────────────────────────────────────
function EquippedItem({ item, deformUniforms }) {
    if (!item) return null;
    if (item.type === 'glb') return <GlbEquippedItem item={item} deformUniforms={deformUniforms} />;
    return <ProceduralEquippedItem item={item} deformUniforms={deformUniforms} />;
}

// ─── Корневой компонент ───────────────────────────────────────────────────────
// deformUniforms — ссылка на world.deformUniforms курицы (те же { value } объекты)
export default function EquippedItems({ equippedItems, deformUniforms }) {
    if (!equippedItems) return null;
    return (
        <>
            {SLOTS.map(slot => {
                const id = equippedItems[slot];
                if (!id) return null;
                const item = itemById(id);
                if (!item) return null;
                return <EquippedItem key={slot} item={item} deformUniforms={deformUniforms} />;
            })}
        </>
    );
}

useGLTF.preload('/models/items.glb');
