import { useGameStore } from '../Logic/store';
import ShopModal from './ShopModal';

const formatDate = (ts) => {
    const d = new Date(ts);
    const day  = d.getDate().toString().padStart(2, '0');
    const mon  = (d.getMonth() + 1).toString().padStart(2, '0');
    const h    = d.getHours().toString().padStart(2, '0');
    const m    = d.getMinutes().toString().padStart(2, '0');
    return `${day}.${mon}  ${h}:${m}`;
};

const MEDAL = ['🥇', '🥈', '🥉'];

const RARITY_THRESH = [
    { min: 100, label: 'LEGENDARY', color: '#ff9900', glow: 'rgba(255,153,0,0.4)' },
    { min: 50,  label: 'EPIC',      color: '#c77dff', glow: 'rgba(199,125,255,0.3)' },
    { min: 20,  label: 'RARE',      color: '#4cc9f0', glow: 'rgba(76,201,240,0.25)' },
    { min: 0,   label: 'COMMON',    color: 'rgba(255,255,255,0.35)', glow: 'none' },
];

function getRarity(score) {
    return RARITY_THRESH.find(r => score >= r.min);
}

export default function LeaderboardMenu() {
    const isOpen       = useGameStore(s => s.isLeaderboardOpen);
    const onBack       = useGameStore(s => s.closeLeaderboard);
    const onClose      = useGameStore(s => s.closeLeaderboardAll);
    const topScores    = useGameStore(s => s.topScores);
    const highScore    = useGameStore(s => s.highScore);

    if (!isOpen) return null;

    const isEmpty = topScores.length === 0;

    return (
        <ShopModal
            title="LEADERBOARD"
            onBack={onBack}
            onClose={onClose}
            width="440px"
            height="600px"
        >
            <div style={{
                height: '100%',
                display: 'flex',
                flexDirection: 'column',
                padding: '0',
                fontFamily: 'monospace',
                overflowY: 'auto',
            }}>
                {/* ── Хедер с лучшим результатом ── */}
                {highScore > 0 && (
                    <div style={{
                        padding: '20px 24px 16px',
                        borderBottom: '1px solid rgba(255,204,0,0.1)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'space-between',
                        background: 'rgba(255,204,0,0.04)',
                        flexShrink: 0,
                    }}>
                        <div>
                            <div style={{ fontSize: '9px', letterSpacing: '3px', color: 'rgba(255,204,0,0.45)', marginBottom: '4px' }}>
                                ALL-TIME BEST
                            </div>
                            <div style={{
                                fontSize: '36px',
                                fontWeight: '900',
                                color: '#ffcc00',
                                textShadow: '0 0 20px rgba(255,204,0,0.5)',
                                lineHeight: 1,
                            }}>
                                {highScore.toString().padStart(4, '0')}
                            </div>
                        </div>
                        <div style={{ fontSize: '42px', opacity: 0.9 }}>🏆</div>
                    </div>
                )}

                {/* ── Список ── */}
                <div style={{ flex: 1, overflowY: 'auto', padding: '8px 0' }}>
                    {isEmpty ? (
                        <div style={{
                            display: 'flex',
                            flexDirection: 'column',
                            alignItems: 'center',
                            justifyContent: 'center',
                            height: '200px',
                            gap: '12px',
                            color: 'rgba(255,255,255,0.2)',
                        }}>
                            <div style={{ fontSize: '40px' }}>🐔</div>
                            <div style={{ fontSize: '11px', letterSpacing: '2px' }}>NO RUNS YET</div>
                            <div style={{ fontSize: '10px', opacity: 0.6 }}>GO PLAY FIRST!</div>
                        </div>
                    ) : (
                        topScores.map((entry, i) => {
                            const rarity  = getRarity(entry.score);
                            const isTop3  = i < 3;
                            const medal   = MEDAL[i] ?? null;

                            return (
                                <div
                                    key={`${entry.score}-${entry.date}`}
                                    style={{
                                        display: 'flex',
                                        alignItems: 'center',
                                        padding: '11px 24px',
                                        borderLeft: isTop3
                                            ? `3px solid ${rarity.color}`
                                            : '3px solid transparent',
                                        background: isTop3
                                            ? `linear-gradient(90deg, rgba(255,204,0,0.06) 0%, transparent 100%)`
                                            : i % 2 === 0 ? 'rgba(255,255,255,0.015)' : 'transparent',
                                        transition: 'background 0.15s',
                                        gap: '14px',
                                    }}
                                >
                                    {/* Место */}
                                    <div style={{
                                        width: '28px',
                                        textAlign: 'center',
                                        flexShrink: 0,
                                    }}>
                                        {medal
                                            ? <span style={{ fontSize: '18px' }}>{medal}</span>
                                            : <span style={{ fontSize: '12px', color: 'rgba(255,204,0,0.3)', fontWeight: 'bold' }}>{i + 1}</span>
                                        }
                                    </div>

                                    {/* Счёт */}
                                    <div style={{ flex: 1, minWidth: 0 }}>
                                        <div style={{
                                            fontSize: isTop3 ? '22px' : '18px',
                                            fontWeight: '900',
                                            color: rarity.color,
                                            textShadow: rarity.glow !== 'none' ? `0 0 10px ${rarity.glow}` : 'none',
                                            lineHeight: 1,
                                        }}>
                                            {entry.score.toString().padStart(4, '0')}
                                        </div>
                                        <div style={{
                                            fontSize: '9px',
                                            letterSpacing: '1.5px',
                                            color: rarity.color,
                                            opacity: 0.55,
                                            marginTop: '2px',
                                        }}>
                                            {rarity.label}
                                        </div>
                                    </div>

                                    {/* Дата */}
                                    <div style={{
                                        fontSize: '10px',
                                        color: 'rgba(255,255,255,0.25)',
                                        flexShrink: 0,
                                        textAlign: 'right',
                                    }}>
                                        {formatDate(entry.date)}
                                    </div>
                                </div>
                            );
                        })
                    )}
                </div>

                {/* ── Футер: кол-во игр ── */}
                {!isEmpty && (
                    <div style={{
                        padding: '12px 24px',
                        borderTop: '1px solid rgba(255,204,0,0.08)',
                        fontSize: '9px',
                        letterSpacing: '2px',
                        color: 'rgba(255,255,255,0.2)',
                        textAlign: 'center',
                        flexShrink: 0,
                    }}>
                        {topScores.length} RUNS RECORDED  ·  TOP 10 SHOWN
                    </div>
                )}
            </div>
        </ShopModal>
    );
}
