import {
    GRID_MAX_X, GRID_MIN_Z, WRAP_BOUNDARY,
    HIT_GRENADE_DZ, HIT_GRENADE_DX, HIT_LOG_DZ, HIT_LOG_DX,
    HIT_LILY_DZ, HIT_LILY_DX, HIT_COIN_DZ, HIT_COIN_DX,
    HIT_MEDAL_DZ, HIT_MEDAL_DX,
} from './constants';

// Фабрика создания нового мира (shape состояния).
export const createWorld = () => ({
    playerRef: null,
    obstacles: [], // Гранаты
    logs: [],      // Бревна
    lilys: [],     // Кувшинки
    windows: [],   // Окна (декор)
    props: [],     // Колонны/Вазы (с хитбоксами)
    waters: new Set(), // Хранилище зон воды
    coins: [],     // Монетки (gold=1, red=5)
    medals: [],    // Части медали (5 штук = неуязвимость 5 сек)
});

// Единственный экземпляр мира на всё приложение.
export const gameState = createWorld();

// Мягкий сброс мира: чистим содержимое, не меняя ссылку на объект.
export const resetWorld = () => {
    gameState.obstacles.length = 0;
    gameState.logs.length = 0;
    gameState.lilys.length = 0;
    gameState.windows.length = 0;
    gameState.props.length = 0;
    gameState.coins.length = 0;
    gameState.medals.length = 0;
    gameState.waters.clear();
    gameState.playerRef = null;
};

export const Physics = {
    // 1. ДВИЖЕНИЕ ОБЪЕКТОВ
    update: (world, delta, multiplier) => {
        // Если по какой-то причине дельта или множитель битые — стопаем расчет
        if (isNaN(delta) || isNaN(multiplier)) return;
        const safeDelta = Math.min(delta, 0.03);

        // Двигаем гранаты
        for (let i = 0; i < world.obstacles.length; i++) {
            const o = world.obstacles[i];
            o.x += safeDelta * o.speed * multiplier * o.direction;

            // Обновляем вращение здесь! 
            // Теперь оно привязано к объекту, а не к индексу в цикле отрисовки.
            // Плавное вращение по всем осям
            o.rotation[0] += safeDelta * o.rotVel[0];
            o.rotation[1] += safeDelta * o.rotVel[1];
            o.rotation[2] += safeDelta * o.rotVel[2];

            if (o.x < -WRAP_BOUNDARY) o.x = WRAP_BOUNDARY;
            if (o.x > WRAP_BOUNDARY) o.x = -WRAP_BOUNDARY;
        }

        // Двигаем бревна
        for (let i = 0; i < world.logs.length; i++) {
            const l = world.logs[i];
            const move = safeDelta * l.speed * multiplier * l.direction;
            l.lastMove = move; // Запоминаем дельту для движения игрока
            l.x += move;

            if (l.x > WRAP_BOUNDARY) l.x -= WRAP_BOUNDARY * 2;
            if (l.x < -WRAP_BOUNDARY) l.x += WRAP_BOUNDARY * 2;
        }
    },

    // Проверка занятости клетки (используем для ПРЕДСКАЗАНИЯ прыжка)
    isCellOccupied: (world, x, z) => {

        // 1. ПРОВЕРКА ГРАНИЦ КАРТЫ (Стены по бокам)
        // Если дорога по X от -5 до 5, то всё что дальше — непроходимо
        if (Math.abs(x) > GRID_MAX_X) return true;

        if (z < GRID_MIN_Z) return true;

        // Проходим по всем пропсам (колонны, деревья)
        for (let i = 0; i < world.props.length; i++) {
            const p = world.props[i];
            // Сравнение по целым числам (сетка)
            // Используем Math.round, чтобы избежать проблем с плавающей точкой 0.000001
            if (Math.round(p.z) === Math.round(z) && Math.round(p.x) === Math.round(x)) {
                return true; // Клетка занята
            }
        }
        return false;
    },

    // 2. ПРОВЕРКА СТОЛКНОВЕНИЯ С ГРАНАТОЙ
    checkGrenadeHit: (world) => {
        const p = world.playerRef?.current;
        if (!p) return null;
        const px = p.position.x, pz = p.position.z;
        for (let i = 0; i < world.obstacles.length; i++) {
            const o = world.obstacles[i];
            if (o.hidden) continue;
            if (Math.abs(o.z - pz) >= HIT_GRENADE_DZ) continue;
            if (Math.abs(o.x - px) <  HIT_GRENADE_DX) return o;
        }
        return null;
    },

    // 3. ПРОВЕРКА: СТОИТ ЛИ ИГРОК НА БРЕВНЕ
    getLogUnderPlayer: (world) => {
        const p = world.playerRef?.current;
        if (!p) return null;
        const pPos = p.position;
        for (let i = 0; i < world.logs.length; i++) {
            const l = world.logs[i];
            const dx = Math.abs(l.x - pPos.x);
            const dz = Math.abs(l.z - pPos.z);
            // Хитбокс бревна (длина ~3 единицы, ширина ~0.8)
            if (dz < HIT_LOG_DZ && dx < HIT_LOG_DX) return l;
        }
        return null;
    },

    // Проверка: стоит ли игрок на кувшинке
    getLilyUnderPlayer: (world) => {
        const p = world.playerRef?.current;
        if (!p) return null;
        const pPos = p.position;
        for (let i = 0; i < world.lilys.length; i++) {
            const l = world.lilys[i];
            const dx = Math.abs(l.x - pPos.x);
            const dz = Math.abs(l.z - pPos.z);
            // Хитбокс кувшинки (обычно меньше бревна, ~0.6-0.8)
            if (dz < HIT_LILY_DZ && dx < HIT_LILY_DX) return l;
        }
        return null;
    },

    // 4. ПРОВЕРКА СБОРА МОНЕТЫ
    checkCoinPickup: (world) => {
        const p = world.playerRef?.current;
        if (!p) return null;
        const px = p.position.x, pz = p.position.z;
        for (let i = 0; i < world.coins.length; i++) {
            const c = world.coins[i];
            if (c.collected) continue;
            if (Math.abs(c.z - pz) >= HIT_COIN_DZ) continue;
            if (Math.abs(c.x - px) <  HIT_COIN_DX) return c;
        }
        return null;
    },

    // 5. ПРОВЕРКА СБОРА МЕДАЛИ
    checkMedalPickup: (world) => {
        const p = world.playerRef?.current;
        if (!p) return null;
        const px = p.position.x, pz = p.position.z;
        for (let i = 0; i < world.medals.length; i++) {
            const m = world.medals[i];
            if (m.collected) continue;
            if (Math.abs(m.z - pz) >= HIT_MEDAL_DZ) continue;
            if (Math.abs(m.x - px) <  HIT_MEDAL_DX) return m;
        }
        return null;
    },
};

// Единый менеджер для регистрации ВСЕГО
export const PhysicsManager = {
    register: (type, data) => {
        if (type === 'window') gameState.windows.push(data);
        if (type === 'prop') gameState.props.push(data);
        if (type === 'obstacle') gameState.obstacles.push(data);
        if (type === 'log') gameState.logs.push({ ...data, lastMove: 0 });
        if (type === 'lily') gameState.lilys.push(data);
        if (type === 'water') gameState.waters.add(data);
        if (type === 'coin') gameState.coins.push(data);
        if (type === 'medal') gameState.medals.push(data);
    },
    remove: (type, id) => {
        if (type === 'water') {
            gameState.waters.delete(id);
            return;
        }
        const typeToKey = {
            'prop': 'props',
            'obstacle': 'obstacles',
            'log': 'logs',
            'lily': 'lilys',
            'window': 'windows',
            'coin': 'coins',
            'medal': 'medals',
        };
        const key = typeToKey[type];
        const arr = gameState[key];
        if (!arr) return;
        const idx = arr.findIndex(item => item.id === id);
        if (idx > -1) arr.splice(idx, 1);
    },
    hideObstacle: (id) => {
        const obs = gameState.obstacles.find(o => o.id === id);
        if (obs) {
            obs.y = -100; // Уводим под текстуры
            obs.speed = 0; // Останавливаем
            obs.hidden = true; // Флаг для рендера
        }
    },
    clearAll: () => {
        // Полностью очищаем мир, не меняя ссылку (важно для контекста).
        resetWorld();
    }
};