import { useEffect, useMemo } from "react";
import { PhysicsManager } from "../Logic/PhysicsEngine";
import { useGameStore } from "../Logic/store";

const PART_TYPES = ['medal_part1','medal_part2','medal_part3','medal_part4','medal_part5'];

export default function Medal({ x, z, subtype = 'medal_part1' }) {
    const id = useMemo(() => `medal-${x}-${z}-${Math.random().toString(36).slice(2)}`, []);

    // Вычисляем фактический тип один раз при монтировании.
    // Если эта часть уже собрана — берём одну из недостающих.
    const effectiveSubtype = useMemo(() => {
        if (!PART_TYPES.includes(subtype)) return subtype; // blue/red — без изменений
        const collected = useGameStore.getState().medalPartsCollected;
        if (!collected.includes(subtype)) return subtype;  // эта часть ещё не собрана
        const missing = PART_TYPES.filter(p => !collected.includes(p));
        if (missing.length === 0) return subtype;           // все собраны (нет в мире)
        // Детерминированный выбор по позиции, чтобы не скакало при ре-рендере
        const idx = Math.abs(Math.floor(Math.sin(x * 12.98 + z * 78.23) * 43758)) % missing.length;
        return missing[idx];
    }, []); // eslint-disable-line — читаем store-snapshot один раз при монтировании

    useEffect(() => {
        const data = {
            id,
            x,
            z,
            subtype: effectiveSubtype,
            collected: false,
            phase: Math.random() * Math.PI * 2,
        };

        PhysicsManager.register('medal', data);
        return () => PhysicsManager.remove('medal', id);
    }, [id, x, z, effectiveSubtype]);

    return null; // Рисует MedalView
}