import { useFrame } from '@react-three/fiber';
import { useRef, useState } from 'react';
import { useWorld } from '../Logic/GameWorldContext';
import { WATER_Y, WATER_BOTTOM_OFFSET, CAUSTICS_Y_OFFSET } from '../Logic/constants';
import { waterRowGeometry, rippleArray, setWaterTime } from './WaterRowMaterial';
import './WaterRowMaterial'; // registers <waterRowMaterial> via extend
import { causticsGeo, causticsMaterial, bottomGeo, bottomMaterial } from './WaterBottomLayers';

const ROT      = [-Math.PI / 2, 0, 0];
const BOTTOM_Y = WATER_Y - WATER_BOTTOM_OFFSET;

export default function WaterEffectsView() {
    const world   = useWorld();
    const matRefs = useRef({});
    const [rows, setRows] = useState([]);
    const lastKey = useRef('');

    useFrame((state) => {
        const t = state.clock.elapsedTime;
        setWaterTime(t);
        causticsMaterial.uniforms.uTime.value = t;
        bottomMaterial.uniforms.uTime.value   = t;
        const waters = world.waters;

        // ── Detect row changes → trigger re-render only when needed ──────────
        const sorted = Array.from(waters).sort((a, b) => a - b);
        const key = sorted.join(',');
        if (key !== lastKey.current) {
            lastKey.current = key;
            setRows(sorted);
        }

        // ── Update uniforms for each visible water material ──────────────────
        const mats = matRefs.current;
        for (let i = 0; i < sorted.length; i++) {
            const mat = mats[sorted[i]];
            if (!mat) continue;
            mat.uTime    = t;
            mat.uRipples = rippleArray;
        }
    });

    return (
        <>
            {rows.map(z => (
                <group key={z}>
                    {/* Дно с fake-рефракцией (vertex displacement) */}
                    <mesh
                        rotation={ROT}
                        position={[0, BOTTOM_Y, z]}
                        geometry={bottomGeo}
                        material={bottomMaterial}
                        receiveShadow
                    />
                    {/* Вода */}
                    <mesh
                        rotation={ROT}
                        position={[0, WATER_Y, z]}
                        geometry={waterRowGeometry}
                        renderOrder={1}
                    >
                        <waterRowMaterial
                            ref={r => { if (r) matRefs.current[z] = r; }}
                            transparent
                            depthWrite={false}
                        />
                    </mesh>
                    {/* Каустики (Worley, AdditiveBlending) — на дне, чуть выше */}
                    <mesh
                        rotation={ROT}
                        position={[0, BOTTOM_Y + CAUSTICS_Y_OFFSET, z]}
                        geometry={causticsGeo}
                        material={causticsMaterial}
                        renderOrder={1}
                        depthWrite={false}
                    />
                </group>
            ))}
        </>
    );
}
