// ── Bottom nav ─────────────────────────────────────────────────────────────────
function BottomNav({ activeTab, onTabChange, onPlay, isReady }) {
    // Подписываемся на open-состояния, чтобы синхронизировать активный таб
    const isChestOpen       = useGameStore(s => s.isChestOpen);
    const isLeaderboardOpen = useGameStore(s => s.isLeaderboardOpen);
    const isWardrobeOpen    = useGameStore(s => s.isWardrobeOpen);

    const openChest           = useGameStore(s => s.openChest);
    const openLeaderboard     = useGameStore(s => s.openLeaderboard);
    const openWardrobe        = useGameStore(s => s.openWardrobe);
    const closeChestAll       = useGameStore(s => s.closeChestAll);
    const closeLeaderboardAll = useGameStore(s => s.closeLeaderboardAll);
    const closeWardrobeAll    = useGameStore(s => s.closeWardrobeAll);

    // Когда модальное окно закрыли через ✕ — снимаем активный таб
    useEffect(() => {
        if (!isChestOpen && activeTab === 'prizes')       onTabChange(null);
    }, [isChestOpen]);
    useEffect(() => {
        if (!isLeaderboardOpen && activeTab === 'top')    onTabChange(null);
    }, [isLeaderboardOpen]);
    useEffect(() => {
        if (!isWardrobeOpen && activeTab === 'shop')      onTabChange(null);
    }, [isWardrobeOpen]);

    // Закрыть все меню + сбросить паузу
    const closeAll = () => {
        closeChestAll();
        closeLeaderboardAll();
        closeWardrobeAll();
        // сбрасываем паузу которую могли поставить для FAQ
        useGameStore.setState({ isPaused: false });
    };

    const selectTab = (tab, openFn = null) => {
        closeAll();
        if (tab === activeTab && !openFn) {
            // toggle FAQ
            onTabChange(null);
        } else {
            onTabChange(tab);
            if (openFn) openFn();
            if (tab === 'faq') useGameStore.setState({ isPaused: true });
        }
    };

    const TABS = [
        {
            id: 'prizes',
            label: 'Prizes',
            Icon: IcoPrizes,
            onPress: () => selectTab('prizes', openChest),
        },
        {
            id: 'top',
            label: 'Top',
            Icon: IcoTop,
            onPress: () => selectTab('top', openLeaderboard),
        },
        {
            id: 'play',
            label: '',
            Icon: IcoPlay,
            onPress: onPlay,
            isPlay: true,
        },
        {
            id: 'shop',
            label: 'Shop',
            Icon: IcoShop,
            onPress: () => selectTab('shop', openWardrobe),
        },
        {
            id: 'faq',
            label: 'F.A.Q',
            Icon: IcoFaq,
            onPress: () => selectTab('faq'),
        },
    ];

    return (
        <div style={{
            position: 'fixed', bottom: 0, left: 0, right: 0,
            zIndex: 300,
            background: NAV_BG,
            borderTop: '1px solid rgba(255,255,255,0.06)',
            paddingBottom: 'env(safe-area-inset-bottom, 0px)',
            display: 'flex', alignItems: 'flex-start',
            height: 'calc(62px + env(safe-area-inset-bottom, 0px))',
        }}>
            {TABS.map(({ id, label, Icon, onPress, isPlay }) => {
                const isActive = activeTab === id;
                const iconColor = isPlay
                    ? '#fff'
                    : isActive ? ORANGE : 'rgba(255,255,255,0.42)';
                const labelColor = isActive ? ORANGE : 'rgba(255,255,255,0.42)';

                return (
                    <button
                        key={id}
                        onPointerDown={onPress}
                        disabled={isPlay && !isReady}
                        style={{
                            flex: 1, height: '62px',
                            background: 'none', border: 'none',
                            cursor: isPlay && !isReady ? 'default' : 'pointer',
                            display: 'flex', flexDirection: 'column',
                            alignItems: 'center', justifyContent: 'center',
                            gap: '5px',
                            WebkitTapHighlightColor: 'transparent',
                            position: 'relative',
                        }}
                    >
                        {isPlay ? (
                            /* ── Центральная кнопка Play ── */
                            <div style={{
                                width: '56px', height: '56px',
                                borderRadius: '50%',
                                background: isReady
                                    ? `linear-gradient(150deg, ${ORANGE} 0%, ${ORANGE_DARK} 100%)`
                                    : 'rgba(100,60,0,0.4)',
                                display: 'flex', alignItems: 'center', justifyContent: 'center',
                                boxShadow: isReady
                                    ? `0 4px 18px rgba(245,166,35,0.55), 0 0 0 3px rgba(245,166,35,0.18)`
                                    : 'none',
                                transition: 'background 0.3s, box-shadow 0.3s',
                                position: 'absolute',
                                top: '-16px',   // поднимаем над панелью
                                opacity: isReady ? 1 : 0.4,
                            }}>
                                <Icon c={iconColor} />
                            </div>
                        ) : (
                            <>
                                <Icon c={iconColor} />
                                <span style={{
                                    fontFamily: FONT,
                                    fontSize: '10px',
                                    fontWeight: '700',
                                    color: labelColor,
                                    letterSpacing: '0.3px',
                                    transition: 'color 0.18s',
                                    lineHeight: 1,
                                }}>{label}</span>
                            </>
                        )}
                    </button>
                );
            })}
        </div>
    );
}

// ── Главный компонент ─────────────────────────────────────────────────────────
export default function Loader() {
    const { active, progress } = useProgress();
    const [isReady, setIsReady]     = useState(false);
    const [isStarted, setIsStarted] = useState(false);
    const [activeTab, setActiveTab] = useState(null);
    const setStarted = useGameStore(s => s.setStarted);

    useEffect(() => {
        if (progress >= 100 && !active) {
            const timer = setTimeout(() => setIsReady(true), 500);
            return () => clearTimeout(timer);
        }
    }, [progress, active]);

    const handleStart = () => {
        if (!isReady) return;
        // Снимаем паузу если была (FAQ)
        useGameStore.setState({ isPaused: false });
        // Закрываем все меню если открыты
        const s = useGameStore.getState();
        s.closeChestAll?.();
        s.closeLeaderboardAll?.();
        s.closeWardrobeAll?.();
        SoundManager.unlock();
        SoundManager.fadeInGlobal(1500);
        SoundManager.startAmbient();
        setIsStarted(true);
        setStarted();
    };

    if (isStarted) return null;

    const showFaq = activeTab === 'faq';

    return (
        <div style={{
            position: 'fixed', inset: 0, zIndex: 9999,
            background: isReady ? 'rgba(0,0,0,0.58)' : '#080510',
            backdropFilter: isReady ? 'blur(7px)' : 'none',
            WebkitBackdropFilter: isReady ? 'blur(7px)' : 'none',
            transition: 'background 0.9s ease',
            color: '#fff',
            overflow: 'hidden',
        }}>

            {/* ── Экран загрузки ── */}
            {!isReady && (
                <div style={{
                    position: 'absolute', inset: 0,
                    display: 'flex', flexDirection: 'column',
                    alignItems: 'center', justifyContent: 'center',
                    gap: '24px',
                }}>
                    <div style={{
                        fontFamily: FONT,
                        fontSize: 'clamp(28px, 9vw, 52px)',
                        fontWeight: '900',
                        color: ORANGE,
                        letterSpacing: '5px',
                        textShadow: `0 0 40px rgba(245,166,35,0.55)`,
                    }}>CHICKPOINT RUSH</div>

                    <div style={{ width: 'min(55%, 200px)' }}>
                        <div style={{
                            height: '3px',
                            background: 'rgba(255,255,255,0.08)',
                            borderRadius: '2px',
                        }}>
                            <div style={{
                                height: '100%', background: ORANGE,
                                width: `${progress}%`,
                                transition: 'width 0.3s',
                                borderRadius: '2px',
                            }} />
                        </div>
                        <p style={{
                            fontFamily: FONT,
                            fontSize: '9px', marginTop: '10px',
                            letterSpacing: '3px',
                            color: 'rgba(255,255,255,0.3)',
                            textAlign: 'center',
                        }}>
                            LOADING {Math.round(progress)}%
                        </p>
                    </div>
                </div>
            )}

            {/* ── Главный экран ── */}
            {isReady && !showFaq && (
                <div style={{
                    position: 'absolute', inset: 0,
                    display: 'flex', flexDirection: 'column',
                    alignItems: 'center', justifyContent: 'center',
                    paddingBottom: 'calc(72px + env(safe-area-inset-bottom, 0px))',
                    paddingTop: 'env(safe-area-inset-top, 24px)',
                    gap: 'clamp(4px, 1.5vh, 12px)',
                }}>
                    {/* Подзаголовок */}
                    <div style={{
                        fontFamily: FONT,
                        fontSize: 'clamp(11px, 3vw, 15px)',
                        letterSpacing: '5px',
                        fontWeight: '700',
                        color: 'rgba(255,255,255,0.92)',
                        textShadow: '0 2px 10px rgba(0,0,0,0.9)',
                    }}>CHICKPOINT</div>

                    {/* Главный заголовок */}
                    <div style={{
                        fontFamily: FONT,
                        fontSize: 'clamp(64px, 20vw, 110px)',
                        fontWeight: '900',
                        color: ORANGE,
                        textShadow: `0 7px 0 ${ORANGE_DARK}, 0 0 50px rgba(245,166,35,0.5)`,
                        letterSpacing: '6px',
                        lineHeight: 1,
                    }}>RUSH</div>

                    {/* Кнопка ИГРАТЬ */}
                    <button
                        onPointerDown={handleStart}
                        style={{
                            marginTop: 'clamp(10px, 2.5vh, 22px)',
                            width: 'min(70vw, 260px)',
                            padding: 'clamp(14px, 3.5vh, 18px) 0',
                            background: `linear-gradient(150deg, ${ORANGE} 0%, ${ORANGE_DARK} 100%)`,
                            border: 'none',
                            borderRadius: '14px',
                            color: '#fff',
                            fontFamily: FONT,
                            fontSize: 'clamp(18px, 5vw, 24px)',
                            fontWeight: '900',
                            letterSpacing: '3px',
                            cursor: 'pointer',
                            boxShadow: `0 6px 28px rgba(245,166,35,0.5), inset 0 1px 0 rgba(255,255,255,0.2)`,
                            WebkitTapHighlightColor: 'transparent',
                            animation: 'lPulse 2.2s ease-in-out infinite',
                        }}
                    >
                        ИГРАТЬ
                    </button>
                </div>
            )}

            {/* ── FAQ экран ── */}
            {isReady && showFaq && <FaqScreen />}

            {/* ── Нижняя навигация ── */}
            {isReady && (
                <BottomNav
                    activeTab={activeTab}
                    onTabChange={setActiveTab}
                    onPlay={handleStart}
                    isReady={isReady}
                />
            )}

            <style>{`
                @keyframes lPulse {
                    0%,100% { transform: scale(1);    box-shadow: 0 6px 28px rgba(245,166,35,0.5),  inset 0 1px 0 rgba(255,255,255,0.2); }
                    50%      { transform: scale(1.025); box-shadow: 0 8px 36px rgba(245,166,35,0.72), inset 0 1px 0 rgba(255,255,255,0.2); }
                }
            `}</style>
        </div>
    );
}
