import { useEffect, useMemo } from "react";
import { PhysicsManager } from "../Logic/PhysicsEngine";

export default function Coin({ x, z, type }) {
    const id = useMemo(() => `coin-${x}-${z}-${Math.random().toString(36).slice(2)}`, []);

    useEffect(() => {
        const data = {
            id,
            x,
            z,
            type,          // 'gold' | 'red'
            collected: false,
            phase: Math.random() * Math.PI * 2, // Уникальная фаза для анимации
        };

        PhysicsManager.register('coin', data);
        return () => PhysicsManager.remove('coin', id);
    }, [id, x, z, type]);

    return null; // Рисует CoinView
}
