import { useRef, Suspense, useState, useMemo, useEffect } from 'react';
import * as THREE from 'three';
import Chicken from '../Player/Chicken';
import EquippedItems from '../Player/EquippedItems';
import { useGameStore } from '../Logic/store';
import { SLOTS, RARITY_COLOR, itemsBySlot, itemById } from './items';

// ─── Сэмплируем средний цвет атрибута вершин ──────────────────────────────────
function sampleAttrColor(attr) {
    if (!attr) return '#888888';
    const count = Math.min(attr.count, 64); // сэмплируем не больше 64 вершин
    let r = 0, g = 0, b = 0;
    const tmp = new THREE.Color();
    for (let i = 0; i < count; i++) {
        tmp.fromBufferAttribute(attr, i);
        r += tmp.r; g += tmp.g; b += tmp.b;
    }
    return `#${new THREE.Color(r / count, g / count, b / count).getHexString()}`;
}

// ─── Хук: получаем цвета всех 5 вариантов из геометрии ───────────────────────
function useChickenColors() {
    const { nodes } = useGLTF('/models/chicken.glb');
    return useMemo(() => {
        const geo = nodes.modelschickenchickenvmdl_cchicken008?.geometry;
        if (!geo) return Array(5).fill('#888888');
        return [
            sampleAttrColor(geo.attributes['color']),
            sampleAttrColor(geo.attributes['color_1']),
            sampleAttrColor(geo.attributes['color_2']),
            sampleAttrColor(geo.attributes['color_3']),
            sampleAttrColor(geo.attributes['color_4']),
        ];
    }, [nodes]);
}

// ─── Курица с надетыми предметами ─────────────────────────────────────────────
function AnimatedChicken({ equippedItems, colorIdx }) {
    const groupRef = useRef();
    useFrame((state) => {
        if (!groupRef.current) return;
        const t = state.clock.elapsedTime;
        groupRef.current.rotation.y = Math.sin(t * 0.6) * 0.18;
        groupRef.current.position.y = Math.sin(t * 1.3) * 0.03 - 0.55;
    });
    return (
        <group ref={groupRef} scale={1.6}>
            <Chicken colorIdx={colorIdx} />
            <EquippedItems equippedItems={equippedItems} />
        </group>
    );
}

// ─── Свотчи цвета курицы с системой покупки ───────────────────────────────────
// ─── Свотчи + панель покупки ──────────────────────────────────────────────────
function ColorPicker({ colors, selected, unlockedItems, totalCoins, onSelect, onBuy }) {
    // preview: null = ничего не выбрано для покупки; число = предпросмотр покупки
    const [preview, setPreview] = useState(null);
    const [justBought, setJustBought] = useState(null);

    const handleSwatch = (i) => {
        const id = `chicken_color_${i}`;
        const isOwned = i === 0 || unlockedItems.includes(id);
        if (isOwned) {
            onSelect(i);
            setPreview(null);
        } else {
            // Показываем на курице, но не покупаем
            onSelect(i);
            setPreview(i);
        }
    };

    const handleBuy = () => {
        if (preview === null) return;
        const ok = onBuy(preview);
        if (ok) {
            setJustBought(preview);
            setPreview(null);
            setTimeout(() => setJustBought(null), 800);
        }
    };

    const previewColor = preview !== null ? colors[preview] : null;
    const canAfford    = totalCoins >= 40;

    return (
        <div style={{
            position: 'absolute',
            bottom: 0, left: 0, right: 0,
            zIndex: 5,
        }}>
            {/* ── Панель покупки ── */}
            {preview !== null && (
                <div style={{
                    margin: '0 12px 8px',
                    padding: '10px 14px',
                    background: 'rgba(8,8,8,0.92)',
                    border: `1px solid ${canAfford ? 'rgba(255,204,0,0.35)' : 'rgba(255,255,255,0.1)'}`,
                    borderRadius: '8px',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '12px',
                    animation: 'buyPanelIn 0.18s ease-out',
                }}>
                    {/* Превью цвета */}
                    <div style={{
                        width: '28px', height: '28px',
                        borderRadius: '50%',
                        background: previewColor,
                        boxShadow: `0 0 10px ${previewColor}99`,
                        flexShrink: 0,
                        border: '2px solid rgba(255,255,255,0.2)',
                    }} />

                    {/* Текст */}
                    <div style={{ flex: 1, minWidth: 0 }}>
                        <div style={{ fontSize: '10px', letterSpacing: '2px', color: '#fff', fontFamily: 'monospace' }}>
                            COLOR {preview}
                        </div>
                        <div style={{
                            fontSize: '9px', letterSpacing: '1px', fontFamily: 'monospace', marginTop: '2px',
                            color: canAfford ? '#ffd700' : '#ff6060',
                        }}>
                            {canAfford ? `COST: 40 🪙` : `NEED: ${40 - totalCoins} MORE 🪙`}
                        </div>
                    </div>

                    {/* Кнопка отмены */}
                    <button
                        onPointerDown={() => { setPreview(null); onSelect(selected === preview ? 0 : selected); }}
                        style={{
                            background: 'none', border: '1px solid rgba(255,255,255,0.15)',
                            color: 'rgba(255,255,255,0.45)', fontSize: '11px',
                            width: '26px', height: '26px', borderRadius: '4px',
                            cursor: 'pointer', padding: 0, flexShrink: 0,
                            WebkitTapHighlightColor: 'transparent',
                        }}
                    >✕</button>

                    {/* Кнопка покупки */}
                    <button
                        onPointerDown={canAfford ? handleBuy : undefined}
                        disabled={!canAfford}
                        style={{
                            padding: '6px 14px',
                            background: canAfford ? '#ffcc00' : 'rgba(255,255,255,0.06)',
                            border: canAfford ? 'none' : '1px solid rgba(255,255,255,0.1)',
                            color: canAfford ? '#000' : 'rgba(255,255,255,0.25)',
                            fontSize: '11px', fontWeight: 'bold', letterSpacing: '1.5px',
                            fontFamily: 'monospace',
                            borderRadius: '4px',
                            cursor: canAfford ? 'pointer' : 'not-allowed',
                            flexShrink: 0,
                            transition: 'background 0.15s, color 0.15s',
                            WebkitTapHighlightColor: 'transparent',
                        }}
                    >
                        BUY
                    </button>
                </div>
            )}

            {/* ── Ряд свотчей ── */}
            <div style={{
                padding: '8px 16px 14px',
                background: 'linear-gradient(to top, rgba(0,0,0,0.82) 0%, transparent 100%)',
                display: 'flex',
                alignItems: 'center',
                gap: '8px',
            }}>
                <div style={{
                    fontSize: '8px', letterSpacing: '2px',
                    color: 'rgba(255,204,0,0.45)',
                    fontFamily: 'monospace',
                    marginRight: '2px', flexShrink: 0,
                }}>
                    COLOR
                </div>

                <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                    {colors.map((hex, i) => {
                        const id       = `chicken_color_${i}`;
                        const isOwned  = i === 0 || unlockedItems.includes(id);
                        const isActive = selected === i;
                        const isPreviewing = preview === i;
                        const isBought = justBought === i;

                        return (
                            <div key={i} style={{ position: 'relative', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '3px' }}>
                                <button
                                    onPointerDown={() => handleSwatch(i)}
                                    style={{
                                        width: (isActive || isPreviewing) ? '36px' : '30px',
                                        height: (isActive || isPreviewing) ? '36px' : '30px',
                                        borderRadius: '50%',
                                        background: isOwned ? hex : `${hex}55`,
                                        border: isActive
                                            ? '2.5px solid #ffcc00'
                                            : isPreviewing
                                                ? '2.5px solid rgba(255,255,255,0.6)'
                                                : isOwned
                                                    ? '2px solid rgba(255,255,255,0.2)'
                                                    : '2px solid rgba(255,255,255,0.1)',
                                        cursor: 'pointer',
                                        padding: 0,
                                        transition: 'width 0.15s, height 0.15s, border-color 0.15s',
                                        boxShadow: isActive
                                            ? `0 0 12px ${hex}, 0 0 24px rgba(255,204,0,0.3)`
                                            : isPreviewing
                                                ? `0 0 8px ${hex}88`
                                                : isOwned ? `0 2px 6px rgba(0,0,0,0.5)` : 'none',
                                        flexShrink: 0,
                                        WebkitTapHighlightColor: 'transparent',
                                        position: 'relative',
                                        animation: isBought ? 'colorBought 0.6s ease-out' : 'none',
                                    }}
                                >
                                    {!isOwned && !isPreviewing && (
                                        <div style={{
                                            position: 'absolute', inset: 0,
                                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                                            fontSize: '11px',
                                        }}>
                                            🔒
                                        </div>
                                    )}
                                </button>
                            </div>
                        );
                    })}
                </div>
            </div>

            <style>{`
                @keyframes colorBought {
                    0%   { transform: scale(1); }
                    35%  { transform: scale(1.5); box-shadow: 0 0 24px #ffcc00; }
                    100% { transform: scale(1); }
                }
                @keyframes buyPanelIn {
                    from { opacity: 0; transform: translateY(6px); }
                    to   { opacity: 1; transform: translateY(0); }
                }
            `}</style>
        </div>
    );
}

// ─── Внутренний компонент читает цвета уже внутри Canvas (GLTFLoader готов) ──
function ColorPickerBridge({ selected, onSelect }) {
    const colors = useChickenColors();
    // Пробрасываем цвета наружу через callback при первом рендере
    const [ready, setReady] = useState(false);
    useEffect(() => { setReady(true); }, []);
    return ready ? (
        // Рендерим через HTML portal — но нам нужно наружу, поэтому используем state-подъём
        // Вместо этого возвращаем через ref trick — просто бросаем event
        null
    ) : null;
    // ^ Нельзя рендерить HTML внутри Canvas. Поднимаем цвета через хук снаружи.
}

// ─── Позиции HTML-слотов ──────────────────────────────────────────────────────
const SLOT_UI = [
    { id: 'head',  label: 'HEAD',  top: '6%',  left: '50%', tx: '-50%' },
    { id: 'neck',  label: 'NECK',  top: '26%', left: '76%', tx: '0'    },
    { id: 'back',  label: 'BACK',  top: '40%', left: '78%', tx: '0'    },
    { id: 'body',  label: 'BODY',  top: '52%', left: '8%',  tx: '0'    },
    { id: 'tail',  label: 'TAIL',  top: '68%', left: '76%', tx: '0'    },
    { id: 'legs',  label: 'LEGS',  top: '84%', left: '50%', tx: '-50%' },
];

// ─── Пикер предметов для выбранного слота ─────────────────────────────────────
function SlotPicker({ slot, equippedItems, unlockedItems, onEquip, onUnequip, onClose }) {
    const items = itemsBySlot(slot);
    const equipped = equippedItems[slot];

    return (
        <div style={{
            position: 'absolute', inset: 0, zIndex: 10,
            background: 'rgba(0,0,0,0.88)',
            backdropFilter: 'blur(6px)',
            display: 'flex', flexDirection: 'column',
            padding: '16px',
            animation: 'pickerFade 0.15s ease-out',
        }}>
            <div style={{ display: 'flex', alignItems: 'center', marginBottom: '16px', gap: '10px' }}>
                <button onPointerDown={onClose} style={btnStyle}>←</button>
                <span style={{
                    flex: 1, textAlign: 'center',
                    fontSize: '10px', letterSpacing: '3px',
                    color: 'rgba(255,204,0,0.6)', fontFamily: 'monospace',
                }}>
                    {slot.toUpperCase()} SLOT
                </span>
                {equipped && (
                    <button onPointerDown={() => { onUnequip(slot); onClose(); }}
                        style={{ ...btnStyle, borderColor: 'rgba(255,80,80,0.4)', color: '#ff8080' }}>
                        REMOVE
                    </button>
                )}
            </div>

            <div style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(2, 1fr)',
                gap: '10px', flex: 1, overflowY: 'auto',
            }}>
                {items.map(item => {
                    const owned     = unlockedItems.includes(item.id);
                    const isEquipped = equipped === item.id;
                    return (
                        <div key={item.id}
                            onPointerDown={() => {
                                if (!owned) return;
                                if (isEquipped) { onUnequip(slot); onClose(); }
                                else { onEquip(slot, item.id); onClose(); }
                            }}
                            style={{
                                padding: '14px 10px',
                                background: isEquipped
                                    ? 'rgba(255,204,0,0.12)'
                                    : owned ? 'rgba(255,255,255,0.05)' : 'rgba(0,0,0,0.3)',
                                border: `1px solid ${isEquipped
                                    ? 'rgba(255,204,0,0.7)'
                                    : RARITY_COLOR[item.rarity] + '44'}`,
                                borderRadius: '6px',
                                cursor: owned ? 'pointer' : 'default',
                                display: 'flex', flexDirection: 'column',
                                alignItems: 'center', gap: '8px',
                                opacity: owned ? 1 : 0.4,
                                transition: 'background 0.15s',
                                position: 'relative',
                            }}
                        >
                            <div style={{
                                width: '32px', height: '32px',
                                background: item.color,
                                borderRadius: item.type === 'sphere' ? '50%' : '4px',
                                boxShadow: `0 0 8px ${item.color}88`,
                            }} />
                            <div style={{ fontFamily: 'monospace', fontSize: '10px', color: owned ? '#fff' : '#666', letterSpacing: '1px' }}>
                                {item.name}
                            </div>
                            <div style={{ fontSize: '7px', letterSpacing: '1px', color: RARITY_COLOR[item.rarity], fontFamily: 'monospace' }}>
                                {item.rarity.toUpperCase()}
                            </div>
                            {!owned && (
                                <div style={{ position: 'absolute', top: '6px', right: '6px', fontSize: '10px', opacity: 0.5 }}>🔒</div>
                            )}
                            {isEquipped && (
                                <div style={{ position: 'absolute', top: '5px', right: '6px', fontSize: '8px', color: '#ffcc00', fontFamily: 'monospace', letterSpacing: '1px' }}>ON</div>
                            )}
                        </div>
                    );
                })}
            </div>

            <style>{`@keyframes pickerFade { from { opacity: 0; } to { opacity: 1; } }`}</style>
        </div>
    );
}

// ─── Компонент-мост: рендерится внутри Canvas, сэмплирует цвета и отдаёт наверх
function ColorSampler({ onColors }) {
    const { nodes } = useGLTF('/models/chicken.glb');
    const fired = useRef(false);
    useFrame(() => {
        if (fired.current) return;
        const geo = nodes.modelschickenchickenvmdl_cchicken008?.geometry;
        if (!geo) return;
        fired.current = true;
        const names = ['color', 'color_1', 'color_2', 'color_3', 'color_4'];
        const colors = names.map(n => sampleAttrColor(geo.attributes[n]));
        onColors(colors);
    });
    return null;
}

const btnStyle = {
    background: 'none',
    border: '1px solid rgba(255,204,0,0.25)',
    color: '#ffcc00', fontSize: '13px',
    padding: '5px 10px', cursor: 'pointer',
    borderRadius: '4px', fontFamily: 'monospace',
    WebkitTapHighlightColor: 'transparent',
};

// ─── Главный компонент ────────────────────────────────────────────────────────
export default function ChickenPreview() {
    const equippedItems   = useGameStore(s => s.equippedItems);
    const unlockedItems   = useGameStore(s => s.unlockedItems);
    const equipItem       = useGameStore(s => s.equipItem);
    const unequipItem     = useGameStore(s => s.unequipItem);
    const chickenColorIdx = useGameStore(s => s.chickenColorIdx);
    const setChickenColor = useGameStore(s => s.setChickenColor);
    const buyChickenColor = useGameStore(s => s.buyChickenColor);
    const totalCoins      = useGameStore(s => s.totalCoins);

    const [activeSlot, setActiveSlot] = useState(null);
    const [swatchColors, setSwatchColors] = useState(null); // null пока не готово

    return (
        <div style={{ position: 'relative', width: '100%', height: '100%' }}>
            {/* 3D Canvas */}
            <Canvas
                camera={{ position: [0, 0.8, 5], fov: 32 }}
                gl={{ antialias: true, alpha: true }}
                style={{ background: 'transparent', width: '100%', height: '100%' }}
            >
                <Suspense fallback={null}>
                    <hemisphereLight args={["#b8d8f8", "#d4a85a", 1.6]} />
                    <directionalLight position={[4, 8, 4]} intensity={3.5} color="#ffcc66" />
                    <directionalLight position={[-6, 4, 8]} intensity={0.6} color="#88bbff" />
                    <AnimatedChicken equippedItems={equippedItems} colorIdx={chickenColorIdx} />
                    <ColorSampler onColors={setSwatchColors} />
                    <OrbitControls
                        enablePan={false} enableZoom={false}
                        minPolarAngle={Math.PI * 0.35}
                        maxPolarAngle={Math.PI * 0.62}
                    />
                </Suspense>
            </Canvas>

            {/* HTML слоты — скрываем когда открыт SlotPicker */}
            {!activeSlot && SLOT_UI.filter(slot => itemsBySlot(slot.id).length > 0).map(slot => {
                const equipped = equippedItems[slot.id];
                const eItem    = equipped ? itemById(equipped) : null;
                return (
                    <div key={slot.id} onPointerDown={() => setActiveSlot(slot.id)} style={{
                        position: 'absolute',
                        top: slot.top, left: slot.left,
                        transform: `translate(${slot.tx}, -50%)`,
                        width: '44px', height: '44px',
                        border: eItem
                            ? `1px solid ${RARITY_COLOR[eItem.rarity]}99`
                            : '1px solid rgba(255,204,0,0.3)',
                        borderRadius: '6px',
                        background: eItem ? `${eItem.color}22` : 'rgba(0,0,0,0.55)',
                        display: 'flex', flexDirection: 'column',
                        alignItems: 'center', justifyContent: 'center',
                        cursor: 'pointer',
                        transition: 'border-color 0.15s, background 0.15s',
                        backdropFilter: 'blur(4px)',
                        gap: '2px',
                    }}
                        onMouseEnter={e => {
                            e.currentTarget.style.borderColor = 'rgba(255,204,0,0.9)';
                            e.currentTarget.style.background = 'rgba(255,204,0,0.12)';
                        }}
                        onMouseLeave={e => {
                            e.currentTarget.style.borderColor = eItem ? `${RARITY_COLOR[eItem.rarity]}99` : 'rgba(255,204,0,0.3)';
                            e.currentTarget.style.background = eItem ? `${eItem.color}22` : 'rgba(0,0,0,0.55)';
                        }}
                    >
                        {eItem
                            ? <div style={{ width: '16px', height: '16px', background: eItem.color, borderRadius: eItem.type === 'sphere' ? '50%' : '3px' }} />
                            : <div style={{ fontSize: '14px', opacity: 0.2, lineHeight: 1 }}>+</div>
                        }
                        <div style={{ fontSize: '6px', letterSpacing: '1px', color: eItem ? RARITY_COLOR[eItem.rarity] : 'rgba(255,204,0,0.4)', fontFamily: 'monospace' }}>
                            {slot.label}
                        </div>
                    </div>
                );
            })}

            {/* Пикер предметов */}
            {activeSlot && (
                <SlotPicker
                    slot={activeSlot}
                    equippedItems={equippedItems}
                    unlockedItems={unlockedItems}
                    onEquip={equipItem}
                    onUnequip={unequipItem}
                    onClose={() => setActiveSlot(null)}
                />
            )}

            {/* Свотчи цвета курицы — показываем только когда нет открытого пикера и цвета готовы */}
            {!activeSlot && swatchColors && (
                <ColorPicker
                    colors={swatchColors}
                    selected={chickenColorIdx}
                    unlockedItems={unlockedItems}
                    totalCoins={totalCoins}
                    onSelect={setChickenColor}
                    onBuy={buyChickenColor}
                />
            )}
        </div>
    );
}
