import { useFrame } from '@react-three/fiber';
import { useRef } from 'react';
import * as THREE from 'three';
import { useWorld } from '../Logic/GameWorldContext';
import { useGameStore } from '../Logic/store';

const MAX_CASTERS   = 16;
const PLANE_SIZE    = 40.0;
const HALF_PLANE    = PLANE_SIZE / 2;
const CASTER_RADIUS = 10; // только объекты в этом радиусе

// Типы теней (w-компонент caster)
const T_PLAYER   = 0;
const T_TREE     = 1;
const T_BUILDING = 2;
const T_COLUMN   = 3;
const T_LOG      = 4;
const T_BOAT     = 5;
const T_GRENADE  = 6;

const PROP_TYPE = { tree: T_TREE, building: T_BUILDING, column1: T_COLUMN, column2: T_COLUMN };
const LOG_TYPE  = { Wooden: T_LOG, Boat: T_BOAT };

const shadowGeo = new THREE.PlaneGeometry(PLANE_SIZE, PLANE_SIZE);

const shadowMat = new THREE.ShaderMaterial({
    transparent: true,
    depthWrite:  false,
    uniforms: {
        uCasters:     { value: Array.from({ length: MAX_CASTERS }, () => new THREE.Vector4()) },
        uCasterCount: { value: 0 },
        uCenter:      { value: new THREE.Vector2() },
    },
    vertexShader: `
        varying vec2 vUV;
        void main() {
            vUV = uv;
            gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
        }
    `,
    fragmentShader: `
        uniform vec4 uCasters[${MAX_CASTERS}];
        uniform int  uCasterCount;
        uniform vec2 uCenter;
        varying vec2 vUV;

        // SDF прямоугольника (центрированный)
        float rectSDF(vec2 p, vec2 b) {
            vec2 q = abs(p) - b;
            return length(max(q, 0.0)) + min(max(q.x, q.y), 0.0);
        }

        // Возвращает SDF-расстояние для типа объекта
        float shapeSDF(vec2 p, int t) {
            if (t == 2) return rectSDF(p, vec2(0.85, 0.62)); // building
            if (t == 4) return rectSDF(p, vec2(1.95, 0.38)); // log
            if (t == 5) return rectSDF(p, vec2(2.15, 0.52)); // boat
            // circle: player/tree/column/grenade
            float r = t == 1 ? 0.52 : t == 3 ? 0.28 : t == 6 ? 0.16 : 0.36;
            return length(p) - r;
        }

        void main() {
            // Мировые XZ (UV.y инвертирован после rotation=-PI/2)
            vec2 worldXZ = vec2(
                uCenter.x + (vUV.x - 0.5) * ${PLANE_SIZE.toFixed(1)},
                uCenter.y - (vUV.y - 0.5) * ${PLANE_SIZE.toFixed(1)}
            );

            // SUN_OFFSET=[8,18,-8] → lightDir=normalize([-8,-18,8])
            const vec2  LIGHT_XZ = vec2(-0.376, 0.376);
            const float LIGHT_Y  = 0.847;

            float totalShadow = 0.0;

            for (int i = 0; i < ${MAX_CASTERS}; i++) {
                if (i >= uCasterCount) break;
                vec4  c    = uCasters[i];
                float h    = c.z;
                int   type = int(c.w);

                // Проекция тени на пол вдоль луча света
                float t  = h / LIGHT_Y;
                vec2  sc = c.xy + LIGHT_XZ * t;

                // SDF-дистанция до контура тени
                float sdf  = shapeSDF(worldXZ - sc, type);

                // Размытие краёв зависит от высоты (выше = мягче)
                float soft = 0.20 + h * 0.22;
                float sh   = (1.0 - smoothstep(-0.14, soft, sdf)) * 0.40;
                totalShadow += sh;
            }

            totalShadow = min(totalShadow, 0.68);
            gl_FragColor = vec4(0.0, 0.0, 0.0, totalShadow);
        }
    `,
});

// Временный массив для сортировки по дистанции
const _cands = [];

export default function ProjectedShadow() {
    const meshRef = useRef();
    const world   = useWorld();
    const projectedShadowsEnabled = useGameStore(s => s.projectedShadowsEnabled);

    useFrame(() => {
        const mesh   = meshRef.current;
        const player = world.playerRef?.current;
        if (!mesh || !player) return;

        mesh.visible = projectedShadowsEnabled;
        if (!projectedShadowsEnabled) return;

        const px = player.position.x;
        const pz = player.position.z;

        mesh.position.set(px, 0.02, pz);

        const u = shadowMat.uniforms;
        u.uCenter.value.set(px, pz);

        // ── Собираем кандидатов с дистанцией² ──────────────────────────────
        _cands.length = 0;

        // Props (деревья, здания, колонны)
        for (const p of world.props) {
            const dx = p.x - px, dz = p.z - pz;
            if (Math.abs(dx) > CASTER_RADIUS || Math.abs(dz) > CASTER_RADIUS) continue;
            _cands.push(dx * dx + dz * dz, p.x, p.z, 0, PROP_TYPE[p.type] ?? T_TREE);
        }

        // Брёвна и лодки
        for (const l of world.logs) {
            const dx = l.x - px, dz = l.z - pz;
            if (Math.abs(dx) > CASTER_RADIUS || Math.abs(dz) > CASTER_RADIUS) continue;
            _cands.push(dx * dx + dz * dz, l.x, l.z, 0, LOG_TYPE[l.type] ?? T_LOG);
        }

        // Гранаты
        if (world.obstacles) {
            for (const g of world.obstacles) {
                const dx = g.x - px, dz = g.z - pz;
                if (Math.abs(dx) > CASTER_RADIUS || Math.abs(dz) > CASTER_RADIUS) continue;
                _cands.push(dx * dx + dz * dz, g.x, g.z, g.y ?? 0, T_GRENADE);
            }
        }

        // ── Заполняем uniforms (без сортировки — нет GC) ───────────────────
        const STRIDE = 5;
        const n = _cands.length / STRIDE;
        let count = 0;

        // Игрок всегда первый
        u.uCasters.value[count++].set(px, pz, player.position.y, T_PLAYER);

        // Объекты в радиусе до лимита, без сортировки
        for (let i = 0; i < n && count < MAX_CASTERS; i++) {
            const idx = i * STRIDE;
            u.uCasters.value[count++].set(
                _cands[idx + 1], _cands[idx + 2],
                _cands[idx + 3], _cands[idx + 4]
            );
        }

        u.uCasterCount.value = count;
    });

    return (
        <mesh
            ref={meshRef}
            geometry={shadowGeo}
            material={shadowMat}
            rotation={[-Math.PI / 2, 0, 0]}
            renderOrder={1}
        />
    );
}
