import { useFrame } from '@react-three/fiber';
import { useRef, useMemo } from 'react';
import * as THREE from 'three';
import { useWorld } from '../Logic/GameWorldContext';
import { useGameStore } from '../Logic/store';
import { MAX_PROP_BLOBS, SHADOW_QUALITY_LOW } from '../Logic/constants';

const temp = new THREE.Object3D();

// Круглая текстура-градиент — тёмная в центре, прозрачная по краям
function makeBlobTexture() {
    const size = 64;
    const canvas = document.createElement('canvas');
    canvas.width = canvas.height = size;
    const ctx = canvas.getContext('2d');
    const grad = ctx.createRadialGradient(size/2, size/2, 0, size/2, size/2, size/2);
    grad.addColorStop(0,    'rgba(0,0,0,0.55)');
    grad.addColorStop(0.4,  'rgba(0,0,0,0.25)');
    grad.addColorStop(1.0,  'rgba(0,0,0,0)');
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, size, size);
    return new THREE.CanvasTexture(canvas);
}

const blobTexture = makeBlobTexture();

const blobGeo = new THREE.PlaneGeometry(1, 1);
const blobMat = new THREE.MeshBasicMaterial({
    map:         blobTexture,
    transparent: true,
    depthWrite:  false,
    opacity:     1,
});

// MAX_PROP_BLOBS imported from constants

export default function BlobShadow() {
    const world        = useWorld();
    const shadowQuality = useGameStore(s => s.shadowQuality);

    // Ref для blob игрока (одиночный mesh)
    const playerBlobRef = useRef();
    // Ref для instanced mesh всех остальных объектов
    const propBlobRef   = useRef();

    // Instanced материал — тот же blobMat
    const instancedMat = useMemo(() => blobMat.clone(), []);

    useFrame(() => {
        if (shadowQuality !== SHADOW_QUALITY_LOW) return;

        // ── Blob под игроком ──────────────────────────────────────────────────
        const player = world.playerRef?.current;
        if (playerBlobRef.current && player) {
            const py = player.position.y;
            // Чем выше — тем больше и прозрачнее
            const scale   = 1.0 + py * 0.35;
            const opacity = Math.max(0, 0.7 - py * 0.12);
            playerBlobRef.current.position.set(player.position.x, 0.01, player.position.z);
            playerBlobRef.current.scale.set(scale, scale, 1);
            playerBlobRef.current.material.opacity = opacity;
        }

        // ── Blobs под пропсами (деревья, здания, колонны) ────────────────────
        const mesh = propBlobRef.current;
        if (!mesh) return;

        let idx = 0;
        for (const p of world.props) {
            if (idx >= MAX_PROP_BLOBS) break;
            temp.position.set(p.x, 0.01, p.z);
            temp.rotation.set(-Math.PI / 2, 0, 0);
            temp.scale.set(1.4, 1.4, 1);
            temp.updateMatrix();
            mesh.setMatrixAt(idx++, temp.matrix);
        }
        // Скрываем неиспользованные инстансы
        const prev = mesh.userData.prevCount ?? 0;
        for (let i = idx; i < prev; i++) {
            temp.position.set(0, -1000, 0);
            temp.scale.setScalar(0);
            temp.updateMatrix();
            mesh.setMatrixAt(i, temp.matrix);
        }
        mesh.userData.prevCount  = idx;
        mesh.count               = Math.max(idx, prev);
        mesh.instanceMatrix.needsUpdate = true;
    });

    if (shadowQuality !== SHADOW_QUALITY_LOW) return null;

    return (
        <>
            {/* Blob под игроком */}
            <mesh
                ref={playerBlobRef}
                rotation={[-Math.PI / 2, 0, 0]}
                position={[0, 0.01, 0]}
                geometry={blobGeo}
                material={blobMat.clone()}
                renderOrder={-1}
            />

            {/* Blobs под всеми пропсами */}
            <instancedMesh
                ref={propBlobRef}
                args={[blobGeo, instancedMat, MAX_PROP_BLOBS]}
                frustumCulled={false}
                renderOrder={-1}
            />
        </>
    );
}
