import gsap from "gsap";
import { useEffect, useRef } from "react";
import { useWorld } from "../Logic/GameWorldContext";

const POOL_SIZE = 3;   // параллельных всплесков
const DROPS    = 10;   // капель на один всплеск

export default function WaterSplash() {
    const world    = useWorld();
    const poolRefs = useRef([]);
    const poolIdx  = useRef(0);

    useEffect(() => {
        world.emitWaterSplash = (x, z) => {
            const idx  = poolIdx.current % POOL_SIZE;
            poolIdx.current = (poolIdx.current + 1) % POOL_SIZE;
            const group = poolRefs.current[idx];
            if (!group) return;

            group.position.set(x, 0.05, z);

            group.children.forEach((mesh) => {
                const angle = Math.random() * Math.PI * 2;
                const r  = 0.08 + Math.random() * 0.5;
                const tx = Math.cos(angle) * r;
                const tz = Math.sin(angle) * r;
                const ty = 0.4 + Math.random() * 1.0;
                const up = 0.16 + Math.random() * 0.08;

                gsap.killTweensOf(mesh.position);
                gsap.killTweensOf(mesh.scale);
                gsap.killTweensOf(mesh.material);

                gsap.set(mesh.position, { x: 0, y: 0, z: 0 });
                gsap.set(mesh.scale,    { x: 1, y: 1, z: 1 });
                gsap.set(mesh.material, { opacity: 0.75 });

                // Вылетают вверх-в стороны
                gsap.to(mesh.position, { x: tx, y: ty, z: tz, duration: up, ease: "power2.out" });
                // Падают обратно
                gsap.to(mesh.position, { y: -0.1, duration: 0.28, ease: "power2.in", delay: up });
                // Уменьшаются
                gsap.to(mesh.scale,    { x: 0.1, y: 0.1, z: 0.1, duration: 0.22, delay: up });
                // Исчезают
                gsap.to(mesh.material, { opacity: 0, duration: 0.18, delay: up + 0.12 });
            });
        };

        return () => { world.emitWaterSplash = null; };
    }, []); // eslint-disable-line

    return (
        <>
            {Array.from({ length: POOL_SIZE }).map((_, pi) => (
                <group key={pi} ref={el => { poolRefs.current[pi] = el; }}>
                    {Array.from({ length: DROPS }).map((_, di) => (
                        <mesh key={di}>
                            <sphereGeometry args={[0.065, 4, 4]} />
                            <meshStandardMaterial
                                color="#99ddff"
                                emissive="#3399bb"
                                emissiveIntensity={0.3}
                                transparent
                                opacity={0}
                                roughness={0.15}
                                metalness={0.2}
                                depthWrite={false}
                            />
                        </mesh>
                    ))}
                </group>
            ))}
        </>
    );
}
