import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls } from '@react-three/drei';
import { useRef, useState, useCallback, Suspense } from 'react';
import * as THREE from 'three';
import { useGameStore } from '../Logic/store';
import { ITEMS, RARITY_COLOR } from './items';

const CHEST_COST = 50;

// Куб-сундук который трясётся
function ChestCube({ shaking }) {
    const meshRef = useRef();
    const shakeRef = useRef({ active: false, time: 0 });

    // Запускаем шейк
    if (shaking && !shakeRef.current.active) {
        shakeRef.current.active = true;
        shakeRef.current.time = 0;
    }

    useFrame((state, delta) => {
        if (!meshRef.current) return;
        const mesh = meshRef.current;

        // Idle покачивание
        mesh.position.y = Math.sin(state.clock.elapsedTime * 1.5) * 0.05;

        // Шейк поверх idle
        if (shakeRef.current.active) {
            shakeRef.current.time += delta;
            const t = shakeRef.current.time;
            const decay = Math.max(0, 1 - t / 0.6);
            mesh.position.x = Math.sin(t * 40) * 0.18 * decay;
            mesh.position.z = Math.cos(t * 35) * 0.1 * decay;
            mesh.rotation.z = Math.sin(t * 30) * 0.2 * decay;
            if (t >= 0.6) {
                shakeRef.current.active = false;
                mesh.position.x = 0;
                mesh.position.z = 0;
                mesh.rotation.z = 0;
            }
        }
    });

    return (
        <mesh ref={meshRef} castShadow>
            <boxGeometry args={[1.2, 1.0, 1.0]} />
            <meshStandardMaterial color="#8B5E3C" roughness={0.7} metalness={0.1} />
            {/* Крышка */}
            <mesh position={[0, 0.58, 0]}>
                <boxGeometry args={[1.22, 0.18, 1.02]} />
                <meshStandardMaterial color="#6B3E1C" roughness={0.7} />
            </mesh>
            {/* Замок */}
            <mesh position={[0, 0.08, 0.52]}>
                <boxGeometry args={[0.22, 0.22, 0.06]} />
                <meshStandardMaterial color="#ffd700" metalness={0.9} roughness={0.1} />
            </mesh>
        </mesh>
    );
}

// Один DOM-партикл (div который анимируется через CSS)
function DomParticle({ x, y, angle, speed, color, size }) {
    const style = {
        position: 'fixed',
        left: x,
        top: y,
        width: size,
        height: size,
        background: color,
        borderRadius: '50%',
        pointerEvents: 'none',
        zIndex: 9999,
        animation: `chestParticle 0.7s ease-out forwards`,
        '--vx': `${Math.cos(angle) * speed}px`,
        '--vy': `${Math.sin(angle) * speed}px`,
    };
    return <div style={style} />;
}

export default function Chest() {
    const totalCoins   = useGameStore(s => s.totalCoins);
    const unlockedItems = useGameStore(s => s.unlockedItems);
    const unlockItem   = useGameStore(s => s.unlockItem);
    const [shaking, setShaking]     = useState(false);
    const [particles, setParticles] = useState([]);
    const [lastReward, setLastReward] = useState(null); // { id, name, color, rarity }
    const buttonRef = useRef();

    const canAfford = totalCoins >= CHEST_COST;
    // Предметы которые ещё не открыты
    const lockedItems = ITEMS.filter(i => !unlockedItems.includes(i.id));
    const allUnlocked = lockedItems.length === 0;

    const handleOpen = useCallback(() => {
        if (!canAfford || allUnlocked) return;

        // Списываем монеты
        const store = useGameStore.getState();
        const newTotal = store.totalCoins - CHEST_COST;
        localStorage.setItem('crossy_total_coins', newTotal);
        useGameStore.setState({ totalCoins: newTotal });

        // Выбираем случайный заблокированный предмет (rare — вес 0.3, common — 0.7)
        const rares   = lockedItems.filter(i => i.rarity === 'rare');
        const commons = lockedItems.filter(i => i.rarity === 'common');
        let pool = Math.random() < 0.35 && rares.length > 0 ? rares : commons;
        if (pool.length === 0) pool = lockedItems;
        const item = pool[Math.floor(Math.random() * pool.length)];
        unlockItem(item.id);
        setLastReward(item);

        // Шейк куба
        setShaking(true);
        setTimeout(() => setShaking(false), 50);

        // Партикли из кнопки
        const rect = buttonRef.current?.getBoundingClientRect();
        const cx = rect ? rect.left + rect.width / 2 : window.innerWidth / 2;
        const cy = rect ? rect.top  + rect.height / 2 : window.innerHeight / 2;
        const COLORS = ['#ffd700', '#fff', '#ffe066', item.color, item.color, '#ffaaaa'];
        const newParticles = Array.from({ length: 24 }, (_, i) => ({
            id: Date.now() + i,
            x: cx, y: cy,
            angle: (i / 24) * Math.PI * 2 + (Math.random() - 0.5) * 0.5,
            speed: 55 + Math.random() * 90,
            color: COLORS[Math.floor(Math.random() * COLORS.length)],
            size: `${4 + Math.random() * 7}px`,
        }));
        setParticles(newParticles);
        setTimeout(() => setParticles([]), 850);
    }, [canAfford, allUnlocked, lockedItems, unlockItem]);

    return (
        <div style={{
            display: 'flex', flexDirection: 'column',
            alignItems: 'center', justifyContent: 'center',
            height: '100%', gap: '24px', padding: '20px',
        }}>
            <div style={{
                fontSize: '10px', letterSpacing: '3px',
                color: 'rgba(255,204,0,0.5)', fontFamily: 'monospace',
                marginBottom: '-8px',
            }}>
                MYSTERY CHEST
            </div>

            {/* 3D куб сундука */}
            <div style={{ width: '200px', height: '200px' }}>
                <Canvas camera={{ position: [0, 0.5, 3.5], fov: 40 }}
                    gl={{ antialias: true, alpha: true }}
                    style={{ background: 'transparent' }}
                >
                    <Suspense fallback={null}>
                        <ambientLight intensity={1.0} />
                        <directionalLight position={[3, 4, 3]} intensity={1.5} castShadow />
                        <pointLight position={[0, 2, 0]} intensity={0.6} color="#ffd700" />
                        <ChestCube shaking={shaking} />
                        <OrbitControls
                            enablePan={false}
                            enableZoom={false}
                            autoRotate
                            autoRotateSpeed={1.5}
                            minPolarAngle={Math.PI * 0.25}
                            maxPolarAngle={Math.PI * 0.65}
                        />
                    </Suspense>
                </Canvas>
            </div>

            {/* Инфо */}
            <div style={{
                textAlign: 'center', color: 'rgba(255,255,255,0.5)',
                fontSize: '12px', fontFamily: 'monospace',
                lineHeight: '1.6', maxWidth: '200px',
            }}>
                Contains a random<br />cosmetic item
            </div>

            {/* Награда — появляется после открытия */}
            {lastReward && (
                <div style={{
                    textAlign: 'center', fontFamily: 'monospace',
                    padding: '8px 16px',
                    background: 'rgba(255,255,255,0.04)',
                    border: `1px solid ${RARITY_COLOR[lastReward.rarity]}44`,
                    borderRadius: '6px',
                    maxWidth: '200px',
                    animation: 'rewardPop 0.4s cubic-bezier(0.34,1.56,0.64,1)',
                }}>
                    <div style={{ fontSize: '8px', letterSpacing: '2px', color: RARITY_COLOR[lastReward.rarity], marginBottom: '4px' }}>
                        {lastReward.rarity.toUpperCase()} ITEM
                    </div>
                    <div style={{ fontSize: '15px', color: lastReward.color, fontWeight: 'bold', letterSpacing: '1px' }}>
                        {lastReward.name}
                    </div>
                    <div style={{ fontSize: '9px', color: 'rgba(255,255,255,0.4)', marginTop: '3px' }}>
                        Now in WARDROBE
                    </div>
                </div>
            )}

            {/* Кнопка */}
            <button
                ref={buttonRef}
                onPointerDown={handleOpen}
                disabled={!canAfford || allUnlocked}
                style={{
                    width: '200px',
                    padding: '16px',
                    background: (canAfford && !allUnlocked)
                        ? 'linear-gradient(135deg, #ffd700, #ffaa00)'
                        : 'rgba(255,255,255,0.05)',
                    border: (canAfford && !allUnlocked)
                        ? '1px solid #ffd700'
                        : '1px solid rgba(255,255,255,0.1)',
                    color: (canAfford && !allUnlocked) ? '#000' : 'rgba(255,255,255,0.2)',
                    fontSize: '14px', fontWeight: 'bold',
                    fontFamily: 'monospace', letterSpacing: '2px',
                    cursor: (canAfford && !allUnlocked) ? 'pointer' : 'default',
                    borderRadius: '6px',
                    transition: 'all 0.2s',
                    boxShadow: (canAfford && !allUnlocked) ? '0 0 20px rgba(255,215,0,0.3)' : 'none',
                    WebkitTapHighlightColor: 'transparent',
                }}
                onMouseEnter={e => { if (canAfford && !allUnlocked) e.currentTarget.style.transform = 'scale(1.04)'; }}
                onMouseLeave={e => { e.currentTarget.style.transform = 'scale(1)'; }}
            >
                {allUnlocked ? 'ALL UNLOCKED' : `OPEN  —  ${CHEST_COST} COINS`}
            </button>

            {/* Баланс */}
            <div style={{
                fontFamily: 'monospace', fontSize: '12px',
                color: canAfford ? '#ffd700' : '#ff4444',
            }}>
                Your coins: {totalCoins}
                {!canAfford && <span style={{ marginLeft: '8px', opacity: 0.7 }}>(need {CHEST_COST - totalCoins} more)</span>}
            </div>

            {/* DOM партикли */}
            {particles.map(p => (
                <DomParticle key={p.id} {...p} />
            ))}

            <style>{`
                @keyframes chestParticle {
                    0%   { transform: translate(0, 0) scale(1); opacity: 1; }
                    100% { transform: translate(var(--vx), var(--vy)) scale(0); opacity: 0; }
                }
                @keyframes rewardPop {
                    0%   { transform: scale(0.5); opacity: 0; }
                    100% { transform: scale(1);   opacity: 1; }
                }
            `}</style>
        </div>
    );
}
