import React from "react";
import { AnubisFloor } from "./AnubisFloor";
import { Row } from "./Row";
import { useMapData } from "./useMapData";
import { MAP_WINDOW_SIZE } from "../Logic/constants";

function Map() {
  const rowsData = useMapData(MAP_WINDOW_SIZE);

  return (
    <group>
      <AnubisFloor rowsData={rowsData} />
      {rowsData.map((row) => (
        <Row key={row.id} row={row} />
      ))}
    </group>
  );
}

export default React.memo(Map);