import { useFrame } from "@react-three/fiber";
import gsap from "gsap";
import { useEffect, useRef } from "react";
import { useGameStore } from "../Logic/store";
import { useWorld } from "../Logic/GameWorldContext";
import {
    SHADOW_MAP_SIZE, SHADOW_BLUR, SHADOW_RADIUS, SHADOW_NORMAL_BIAS,
    SUN_INTENSITY, SUN_OFFSET, HEMI_INTENSITY, FILL_INTENSITY,
    SHADOW_QUALITY_HIGH,
} from "../Logic/constants";

export default function Lights() {
  const sunRef   = useRef();
  const flashRef = useRef();
  const { isDead, explosionPos, shadowQuality } = useGameStore();
  const world    = useWorld();
  const isHigh   = shadowQuality === SHADOW_QUALITY_HIGH;

  useEffect(() => {
    const light = sunRef.current;
    if (!light || !isHigh) return;
    light.shadow.blurSamples = SHADOW_BLUR;
    light.shadow.radius      = SHADOW_RADIUS;
    light.shadow.bias        = 0.0;
    light.shadow.normalBias  = SHADOW_NORMAL_BIAS;
    light.shadow.mapSize.set(SHADOW_MAP_SIZE, SHADOW_MAP_SIZE);
    if (light.shadow.map) { light.shadow.map.dispose(); light.shadow.map = null; }
  }, [isHigh]);

  useEffect(() => {
    if (isDead && flashRef.current && explosionPos) {
      flashRef.current.position.set(...explosionPos);
      gsap.fromTo(flashRef.current,
        { intensity: 60, distance: 5 },
        { intensity: 0,  distance: 22, duration: 0.45, ease: "power2.out" }
      );
    }
  }, [isDead, explosionPos]);

  useFrame(() => {
    const player = world.playerRef?.current;
    if (!sunRef.current || !player) return;
    const { x, z } = player.position;
    sunRef.current.position.set(x + SUN_OFFSET[0], SUN_OFFSET[1], z + SUN_OFFSET[2]);
    sunRef.current.target.position.set(x, 0, z);
    sunRef.current.target.updateMatrixWorld();
  });

  return (
    <>
      <hemisphereLight args={["#ffefd0", "#c47830", HEMI_INTENSITY]} />

      <directionalLight
        ref={sunRef}
        castShadow={isHigh}
        intensity={SUN_INTENSITY}
        color="#fffbec"
      >
        <orthographicCamera attach="shadow-camera" args={[-12, 12, 12, -9, 0.5, 35]} />
      </directionalLight>

      <directionalLight intensity={FILL_INTENSITY} color="#88bbff" position={[-6, 4, 8]} />
      <pointLight ref={flashRef} color="#ff6622" intensity={0} />
    </>
  );
}
