import { useEffect, useMemo } from "react";
import { PhysicsManager } from "../Logic/PhysicsEngine";
import { useWorld } from "../Logic/GameWorldContext";

export default function Grenade({ z, config, offset, index }) {
    const id = useMemo(() => Math.random().toString(36), []);
    const world = useWorld();

    useEffect(() => {
        const minDistance = 3; // Минимальное расстояние между гранатами

        // Начальный X на основе индекса (например, 0, 8, 16...)
        let safeX = ((index * 8 + 12) % 24) - 12;
        
        // Проверяем, не слишком ли близко к другим гранатам
        const othersOnSameRow = world.obstacles.filter(o => o.z === z);

        for (let i = 0; i < othersOnSameRow.length; i++) { // Пытаемся найти безопасное место до 10 раз
            const other = othersOnSameRow[i]
            if (other && Math.abs(other.x - safeX) < minDistance) {
                safeX += minDistance; // Сдвигаем вправо
                if (safeX > 12) safeX -= 24; // Если вышли за правый край, начинаем с левого
            }
        }

        const data = {
            id,
            z,
            x: safeX,
            speed: config.speed,
            direction: config.direction,
            type: config.type || "HE",

            // Вектор скорости вращения по 3 осям (от -5 до 5 радиан)
            rotVel: [
                (Math.random() - 0.5) * 6,
                (Math.random() - 0.5) * 6,
                (Math.random() - 0.5) * 6
            ],
            // Текущие углы
            rotation: [Math.random(), Math.random(), Math.random()],
            phase: Math.random() * Math.PI * 2, // Случайная фаза для анимации
        };

        PhysicsManager.register('obstacle', data);
        return () => PhysicsManager.remove('obstacle', id);
    }, [id, z, config, offset]);

    return null; // Ничего не рисуем здесь! Рисует GrenadeInstances.
}