import { useEffect, useMemo } from "react";
import { PhysicsManager } from "../Logic/PhysicsEngine";

export default function WallWindow({ z, x, ...props }) {
    const id = useMemo(() => Math.random().toString(36).substr(2, 9), []);

    useEffect(() => {
        PhysicsManager.register('window', { id, z, x });
        return () => PhysicsManager.remove('window', id);
    }, [z, x]);

    return null; // Отрисовка уходит в WindowView
}