import { useGLTF } from '@react-three/drei';
import { useFrame } from '@react-three/fiber';
import { useRef, useMemo, useLayoutEffect } from 'react';
import * as THREE from 'three';
import { useWorld } from '../Logic/GameWorldContext';
import { MAX_MEDALS } from '../Logic/constants';

const temp = new THREE.Object3D();

const medalMaterial = new THREE.MeshStandardMaterial({
    vertexColors: true,
    metalness: 0,
    roughness: 0.1,
});

const sparkGeometry = new THREE.OctahedronGeometry(0.045, 0);
const sparkMat = new THREE.MeshBasicMaterial({ color: '#ffd700' });
const IDLE_SPARKS_PER_MEDAL = 6;
const COLLECT_ANIM_DURATION = 0.9;
const MAX_SPARKS = MAX_MEDALS * IDLE_SPARKS_PER_MEDAL;

const MEDAL_TYPES = ['medal_part1','medal_part2','medal_part3','medal_part4','medal_part5','medal_blue','medal_red'];

export default function MedalView() {
    const { nodes } = useGLTF('/models/medal.glb');

    const geos = useMemo(() => {
        const map = {};
        for (const key of MEDAL_TYPES) map[key] = nodes[key]?.geometry ?? null;
        return map;
    }, [nodes]);

    // one ref per medal type + one for sparks
    const meshRefs = useRef(Object.fromEntries(MEDAL_TYPES.map(k => [k, null])));
    const sparkRef = useRef();
    const world = useWorld();

    useLayoutEffect(() => {
        for (const key of MEDAL_TYPES) {
            const r = meshRefs.current[key];
            if (r) r.count = 0;
        }
        if (sparkRef.current) sparkRef.current.count = 0;
    }, [geos]);

    useFrame((state) => {
        const time = state.clock.elapsedTime;
        const medals = world.medals;
        const sparkMesh = sparkRef.current;

        // counters per type
        const idx = Object.fromEntries(MEDAL_TYPES.map(k => [k, 0]));
        let sparkIdx = 0;

        for (let i = 0; i < medals.length; i++) {
            const m = medals[i];
            const subtype = m.subtype ?? 'medal_part1';
            const mesh = meshRefs.current[subtype];
            if (!mesh) continue;

            if (m.collected) {
                if (m.collectTime === undefined) m.collectTime = time;
                const t = (time - m.collectTime) / COLLECT_ANIM_DURATION;
                if (t >= 1) continue;
                const flyY  = (m.floatY ?? 0.7) + t * 5.0;
                const scale = Math.max(0, 1.0 - t * t * 1.3);
                temp.position.set(m.x, flyY, m.z);
                temp.rotation.set(0, time * (8 + t * 12), 0);
                temp.scale.setScalar(scale);
            } else {
                const floatY   = 0.7 + Math.sin(time * 1.4 + m.phase) * 0.18;
                const bobScale = 1.0 + Math.sin(time * 2.5 + m.phase) * 0.06;
                m.floatY = floatY;
                temp.position.set(m.x, floatY, m.z);
                // Покачивание: наклон вперёд-назад и влево-вправо, без вращения
                const swayX = Math.sin(time * 1.1 + m.phase) * 0.22;
                const swayZ = Math.cos(time * 0.9 + m.phase + 1.0) * 0.18;
                temp.rotation.set(swayX, Math.PI, swayZ);
                temp.scale.setScalar(bobScale);
                temp.updateMatrix();
                // Записываем матрицу медали ДО изменения temp искрами
                mesh.setMatrixAt(idx[subtype]++, temp.matrix);
                // Idle sparks — inline, floatY уже вычислен
                if (sparkMesh) {
                    for (let j = 0; j < IDLE_SPARKS_PER_MEDAL; j++) {
                        const phase  = m.phase + j * (Math.PI * 2 / IDLE_SPARKS_PER_MEDAL);
                        const radius = 0.5 + Math.sin(time * 2.2 + phase * 1.5) * 0.12;
                        temp.position.set(
                            m.x + Math.cos(time * 1.6 + phase) * radius,
                            floatY + Math.sin(time * 3.0 + phase * 2.5) * 0.2,
                            m.z + Math.sin(time * 1.6 + phase) * radius,
                        );
                        temp.rotation.set(time + phase, time * 0.9, 0);
                        temp.scale.setScalar(0.5 + Math.abs(Math.sin(time * 3.5 + phase)) * 0.5);
                        temp.updateMatrix();
                        sparkMesh.setMatrixAt(sparkIdx++, temp.matrix);
                    }
                }
                continue; // setMatrixAt уже вызван выше
            }

            temp.updateMatrix();
            mesh.setMatrixAt(idx[subtype]++, temp.matrix);
        }

        for (const key of MEDAL_TYPES) {
            const mesh = meshRefs.current[key];
            if (mesh) { mesh.count = idx[key]; mesh.instanceMatrix.needsUpdate = true; }
        }

        if (sparkMesh) {
            sparkMesh.count = sparkIdx;
            sparkMesh.instanceMatrix.needsUpdate = true;
        }
    });

    return (
        <group>
            {MEDAL_TYPES.map(key => geos[key] ? (
                <instancedMesh
                    key={key}
                    ref={el => { meshRefs.current[key] = el; }}
                    args={[geos[key], medalMaterial, MAX_MEDALS]}
                    castShadow
                    frustumCulled={false}
                />
            ) : null)}
            <instancedMesh ref={sparkRef} args={[sparkGeometry, sparkMat, MAX_SPARKS]} frustumCulled={false} />
        </group>
    );
}

useGLTF.preload('/models/medal.glb');
