import React, { useEffect } from "react";
import * as THREE from "three";
import AnubisProp from "../Scene/AnubisProp";
import Coin from "../Scene/Coin";
import Medal from "../Scene/Medal";
import Grenade from "../Scene/Grenade";
import LilyPad from "../Scene/LilyPad";
import Log from "../Scene/Log";
import Wall from "../Scene/Wall";
import { PhysicsManager } from "../Logic/PhysicsEngine";


export const Row = React.memo(({ row }) => {
    useEffect(() => {
        if (row.type === 'water') {
            PhysicsManager.register('water', row.z);
            return () => PhysicsManager.remove('water', row.z);
        }
    }, [row.z, row.type]);

    
    return (
        <group position={ [0, 0, row.z] }>

            {/* РЯД С МАШИНАМИ (ГРАНАТАМИ) */ }
            { row.type === "road" && row.config && (
                <>
                    { Array.from({ length: row.config.count }).map((_, i) => (
                        <Grenade
                            key={ `${ row.z }-${ i }` }
                            z={ row.z }
                            config={ row.config }
                            // Рассчитываем отступ на основе конфига из useMapData
                            index= { i }
                        />
                    )) }
                </>
            ) }

            {/* РЯД С ВОДОЙ (ЛОДКИ / ЛИЛИИ) */ }
            { row.type === "water" && row.config && (
                <>
                    {/* Визуал воды — переиспользуем shared геометрию и материал */ }


                    {/* Регистрация лодок */ }
                    { (row.config.type === "Wooden" || row.config.type === "Boat") && row.config.offsets.map((offset, i) => (
                        <Log key={ i } z={ row.z } offset={ offset } config={ row.config } />
                    )) }

                    {/* Регистрация лилий */ }
                    { row.config.type === "lilys" && row.config.lilys.map((lx, i) => (
                        <LilyPad key={ i } x={ lx } z={ row.z } />
                    )) }
                </>
            ) }

            {/* ДЕКОР (ОКНА) */ }
            { row.windows && row.windows.map((x, i) => (
                <Wall key={ i } z={ row.z } x={ x } />
            )) }

            { row.props && row.props.map((p, i) => (
                <AnubisProp
                    key={ i }
                    z={ row.z }
                    x={ Math.round(p.x) }
                    type={ p.type }
                />
            )) }

            {/* МОНЕТЫ */ }
            { row.coins && row.coins.map((c, i) => (
                <Coin key={ i } x={ c.x } z={ row.z } type={ c.type } />
            )) }

            {/* МЕДАЛИ */ }
            { row.medals && row.medals.map((m, i) => (
                <Medal key={ i } x={ m.x } z={ row.z } subtype={ m.subtype } />
            )) }

        </group>
    );
}, (prev, next) => prev.row.id === next.row.id);