import { useEffect, useMemo } from "react";
import { PhysicsManager } from "../Logic/PhysicsEngine";

export default function Log({ z, config, offset }) {
    const id = useMemo(() => Math.random().toString(36), []);
    
    useEffect(() => {
        const data = {
            id,
            z,
            x: offset || 0,
            speed: config.speed,
            direction: config.direction,
            type: config.type || "Wooden",
            yOffset: 0 // Для анимации погружения в воду
        };
        
        PhysicsManager.register('log', data);
        return () => PhysicsManager.remove('log', id);
    }, [id, z, config, offset]);

    return null; 
}