import { useGLTF } from '@react-three/drei';
import { useFrame } from '@react-three/fiber';
import { useEffect, useRef, useState } from 'react';
import * as THREE from 'three';
import { sharedAnubisMaterial, sharedAtlasMaterial, sharedShadowMaterial, sharedGrenadeMaterial, transpPointsUniform } from './sharedMaterial';
import { useWorld } from '../Logic/GameWorldContext';
import {
    POOL_OBSTACLE_BOX, POOL_OBSTACLE_PALM, POOL_OBSTACLE_PILLAR, POOL_OBSTACLE_STATUE, POOL_OBSTACLE_TOWER,
    POOL_WALL, POOL_WOODEN, POOL_BOAT, POOL_LILY,
    POOL_GRENADE_HE, POOL_GRENADE_FLASH, POOL_GRENADE_MOLOTOV,
    POOL_WATERSIDE,
    WATER_Y, WATER_BOTTOM_OFFSET,
} from '../Logic/constants';

const SHADOW_Y_GROUND = 0.02;
const SHADOW_Y_WATER  = WATER_Y - WATER_BOTTOM_OFFSET + 0.01;

const temp = new THREE.Object3D();

const WALL_VARIANTS = ['wallA', 'wallB', 'wallC', 'wallD', 'wallE'];
const WALL_POOL_PER = Math.ceil(POOL_WALL / 5);

// ── Atlas batch — всё с sharedAtlasMaterial ───────────────────────────────────
const POOL_ATLAS = {
    obstacle_box:    POOL_OBSTACLE_BOX,
    obstacle_palm:   POOL_OBSTACLE_PALM,
    obstacle_pillar: POOL_OBSTACLE_PILLAR,
    obstacle_statue: POOL_OBSTACLE_STATUE,
    obstacle_tower:  POOL_OBSTACLE_TOWER,
    wooden:          POOL_WOODEN,
    boat:            POOL_BOAT,
    lily:            POOL_LILY,
    waterside:       POOL_WATERSIDE,
};

// ── Grenade batch — блестящий металлический материал ──────────────────────────
const POOL_GRENADE_BATCH = {
    grenade_HE:      POOL_GRENADE_HE,
    grenade_Flash:   POOL_GRENADE_FLASH,
    grenade_Molotov: POOL_GRENADE_MOLOTOV,
};

// ── Main batch — только стены (sharedAnubisMaterial) ──────────────────────────
const POOL_MAIN = {
    wallA: WALL_POOL_PER,
    wallB: WALL_POOL_PER,
    wallC: WALL_POOL_PER,
    wallD: WALL_POOL_PER,
    wallE: WALL_POOL_PER,
};

const TOTAL_ATLAS   = Object.values(POOL_ATLAS).reduce((s, n) => s + n, 0);
const TOTAL_MAIN    = Object.values(POOL_MAIN).reduce((s, n) => s + n, 0);
const TOTAL_GRENADE = Object.values(POOL_GRENADE_BATCH).reduce((s, n) => s + n, 0);

const PROP_TYPE_TO_KEY = {
    obstacle_box:    'obstacle_box',
    obstacle_palm:   'obstacle_palm',
    obstacle_pillar: 'obstacle_pillar',
    obstacle_statue: 'obstacle_statue',
    obstacle_tower:  'obstacle_tower',
};

const SHADOW_GEO_KEYS = ['shadow_box', 'shadow_palm', 'shadow_pillar', 'shadow_statue', 'shadow_tower', 'shadow_boat', 'shadow_lilly', 'shadow_wooden'];

const PROP_TO_SHADOW = {
    obstacle_box:    'shadow_box',
    obstacle_palm:   'shadow_palm',
    obstacle_pillar: 'shadow_pillar',
    obstacle_statue: 'shadow_statue',
    obstacle_tower:  'shadow_tower',
};

const SHADOW_POOL = {
    shadow_box:    POOL_OBSTACLE_BOX,
    shadow_palm:   POOL_OBSTACLE_PALM,
    shadow_pillar: POOL_OBSTACLE_PILLAR,
    shadow_statue: POOL_OBSTACLE_STATUE,
    shadow_tower:  POOL_OBSTACLE_TOWER,
    shadow_boat:   POOL_BOAT,
    shadow_lilly:  POOL_LILY,
    shadow_wooden: POOL_WOODEN,
};

const TOTAL_SHADOW = Object.values(SHADOW_POOL).reduce((s, n) => s + n, 0);

const _grenadeLight = new THREE.Color(1, 1, 1);
const _grenadeDark  = new THREE.Color(0.45, 0.45, 0.45);
const _grenadeColor = new THREE.Color();

const _propCounts   = { obstacle_box: 0, obstacle_palm: 0, obstacle_pillar: 0, obstacle_statue: 0, obstacle_tower: 0 };
const _wallCounts   = { wallA: 0, wallB: 0, wallC: 0, wallD: 0, wallE: 0 };
const _logCounts    = { wooden: 0, boat: 0 };
const _grenCounts   = { HE: 0, Flash: 0, Molotov: 0 };
const _shadowCounts = { shadow_box: 0, shadow_palm: 0, shadow_pillar: 0, shadow_statue: 0, shadow_tower: 0, shadow_boat: 0, shadow_lilly: 0, shadow_wooden: 0 };

export default function BatchedWorldView() {
    const world = useWorld();

    const { nodes: obsNodes    } = useGLTF('/models/obstacle.glb');
    const { nodes: wallNodes   } = useGLTF('/models/wallwindow.glb');
    const { nodes: woodNodes   } = useGLTF('/models/wooden.glb');
    const { nodes: boatNodes   } = useGLTF('/models/boat.glb');
    const { nodes: lilyNodes   } = useGLTF('/models/lilly.glb');
    const { nodes: grenNodes   } = useGLTF('/models/grenade.glb');
    const { nodes: sideNodes   } = useGLTF('/models/waterside.glb');
    const { nodes: shadowNodes } = useGLTF('/models/shadow.glb');

    const [batches, setBatches] = useState(null);
    const poolsRef   = useRef({});
    const prevCounts = useRef({});

    useEffect(() => {
        const geoMapAtlas = {
            obstacle_box:    obsNodes.obstacle_box?.geometry,
            obstacle_palm:   obsNodes.obstacle_palm?.geometry,
            obstacle_pillar: obsNodes.obstacle_pillar?.geometry,
            obstacle_statue: obsNodes.obstacle_statue?.geometry,
            obstacle_tower:  obsNodes.obstacle_tower?.geometry,
            wooden:          woodNodes.modelsanubismarketwooden_walkwayvmdl_cwooden_walkway_bg_mybody_lod0002?.geometry,
            boat:            boatNodes.Model_Boat002005?.geometry,
            lily:            lilyNodes.lily_001?.geometry,
            waterside:       Object.values(sideNodes).find(n => n.isMesh)?.geometry,
        };

        const geoMapGrenade = {
            grenade_HE:      grenNodes.weaponsmodelsgrenadehegrenadeweapon_hegrenadevmdl_cbody001?.geometry,
            grenade_Flash:   grenNodes.weaponsmodelsgrenadeflashbangweapon_flashbangvmdl_cbody002?.geometry,
            grenade_Molotov: grenNodes.weaponsmodelsgrenademolotovweapon_molotovvmdl_cbody007?.geometry,
        };

        const geoMapMain = {
            wallA: wallNodes.wallA?.geometry,
            wallB: wallNodes.wallB?.geometry,
            wallC: wallNodes.wallC?.geometry,
            wallD: wallNodes.wallD?.geometry,
            wallE: wallNodes.wallE?.geometry,
        };

        const geoMapShadow = {};
        for (const k of SHADOW_GEO_KEYS) {
            const node = shadowNodes[k];
            if (!node?.geometry) return;
            geoMapShadow[k] = node.geometry.clone();
        }

        if (Object.values(geoMapAtlas).some(g => !g)) return;
        if (Object.values(geoMapMain).some(g => !g)) return;
        if (Object.values(geoMapGrenade).some(g => !g)) return;

        const calcSize = (geoMap) => {
            let verts = 0, idx = 0;
            Object.values(geoMap).forEach(geo => {
                verts += geo.attributes.position.count;
                idx   += geo.index ? geo.index.count : geo.attributes.position.count;
            });
            return { verts, idx };
        };

        const atlasSize = calcSize(geoMapAtlas);
        const mainSize  = calcSize(geoMapMain);

        const bAtlas = new THREE.BatchedMesh(TOTAL_ATLAS, atlasSize.verts, atlasSize.idx, sharedAtlasMaterial);
        bAtlas.castShadow             = true;
        bAtlas.receiveShadow          = true;
        bAtlas.frustumCulled          = false;
        bAtlas.perObjectFrustumCulled = false;

        const bMain = new THREE.BatchedMesh(TOTAL_MAIN, mainSize.verts, mainSize.idx, sharedAnubisMaterial);
        bMain.castShadow             = true;
        bMain.receiveShadow          = true;
        bMain.frustumCulled          = false;
        bMain.perObjectFrustumCulled = false;

        const pools = {};

        const stripExtras = (geo) => {
            ['uv1', 'uv2', 'uv3'].forEach(attr => { if (geo.attributes[attr]) geo.deleteAttribute(attr); });
            return geo;
        };

        const addToBatch = (b, poolDef, geoMap) => {
            Object.entries(geoMap).forEach(([key, geo]) => {
                const geoId = b.addGeometry(stripExtras(geo));
                const ids   = [];
                for (let i = 0; i < poolDef[key]; i++) {
                    const id = b.addInstance(geoId);
                    b.setVisibleAt(id, false);
                    ids.push(id);
                }
                pools[key] = { b, ids };
            });
        };

        addToBatch(bAtlas, POOL_ATLAS, geoMapAtlas);
        addToBatch(bMain,  POOL_MAIN,  geoMapMain);

        // ── Grenade BatchedMesh ───────────────────────────────────────────────
        const grenadeSize = calcSize(geoMapGrenade);
        const bGrenade = new THREE.BatchedMesh(TOTAL_GRENADE, grenadeSize.verts, grenadeSize.idx, sharedGrenadeMaterial);
        bGrenade.castShadow             = true;
        bGrenade.frustumCulled          = false;
        bGrenade.perObjectFrustumCulled = false;
        addToBatch(bGrenade, POOL_GRENADE_BATCH, geoMapGrenade);

        // ── Shadow BatchedMesh ────────────────────────────────────────────────
        const shadowSize = calcSize(geoMapShadow);
        const bShadow = new THREE.BatchedMesh(TOTAL_SHADOW, shadowSize.verts, shadowSize.idx, sharedShadowMaterial);
        bShadow.frustumCulled          = false;
        bShadow.perObjectFrustumCulled = false;
        bShadow.renderOrder            = 1;
        addToBatch(bShadow, SHADOW_POOL, geoMapShadow);

        poolsRef.current  = pools;
        prevCounts.current = Object.fromEntries(
            [...Object.keys(POOL_ATLAS), ...Object.keys(POOL_MAIN), ...Object.keys(POOL_GRENADE_BATCH), ...SHADOW_GEO_KEYS].map(k => [k, 0])
        );
        setBatches({ atlas: bAtlas, main: bMain, grenade: bGrenade, shadow: bShadow });

        return () => {
            bAtlas.dispose(); bMain.dispose(); bGrenade.dispose(); bShadow.dispose();
            setBatches(null);
        };
    }, [obsNodes, wallNodes, woodNodes, boatNodes, lilyNodes, grenNodes, sideNodes, shadowNodes]);

    useFrame((state) => {
        if (!batches) return;
        const pools = poolsRef.current;
        const prev  = prevCounts.current;
        const time  = state.clock.elapsedTime;

        const show = (key, idx, matrix) => {
            const entry = pools[key];
            if (!entry || idx >= entry.ids.length) return;
            entry.b.setMatrixAt(entry.ids[idx], matrix);
            entry.b.setVisibleAt(entry.ids[idx], true);
        };

        _shadowCounts.shadow_box = _shadowCounts.shadow_palm = _shadowCounts.shadow_pillar =
        _shadowCounts.shadow_statue = _shadowCounts.shadow_tower = _shadowCounts.shadow_boat =
        _shadowCounts.shadow_lilly = _shadowCounts.shadow_wooden = 0;
        const showShadow = (shadowKey, x, z, y = SHADOW_Y_GROUND) => {
            const idx = _shadowCounts[shadowKey]++;
            temp.position.set(x, y, z);
            temp.rotation.set(0, 0, 0);
            temp.scale.set(1, 1, 1);
            temp.updateMatrix();
            show(shadowKey, idx, temp.matrix);
        };

        const commit = (key, newCount) => {
            const entry = pools[key];
            if (!entry) return;
            const oldCount = prev[key] ?? 0;
            for (let i = newCount; i < oldCount; i++) entry.b.setVisibleAt(entry.ids[i], false);
            prev[key] = newCount;
        };

        // ── Пропсы ────────────────────────────────────────────────────────────
        _propCounts.obstacle_box = _propCounts.obstacle_palm = _propCounts.obstacle_pillar =
        _propCounts.obstacle_statue = _propCounts.obstacle_tower = 0;
        for (const p of world.props) {
            const key = PROP_TYPE_TO_KEY[p.type] ?? 'obstacle_pillar';
            const idx = _propCounts[key]++;
            temp.position.set(p.x, 0, p.z);
            temp.rotation.set(0, (p.id.length % 4) * (Math.PI / 2), 0);
            temp.scale.set(1, 1, 1);
            temp.updateMatrix();
            show(key, idx, temp.matrix);
            showShadow(PROP_TO_SHADOW[p.type] ?? 'shadow_pillar', p.x, p.z);
        }
        commit('obstacle_box',    _propCounts.obstacle_box);
        commit('obstacle_palm',   _propCounts.obstacle_palm);
        commit('obstacle_pillar', _propCounts.obstacle_pillar);
        commit('obstacle_statue', _propCounts.obstacle_statue);
        commit('obstacle_tower',  _propCounts.obstacle_tower);

        // ── Стены ─────────────────────────────────────────────────────────────
        _wallCounts.wallA = _wallCounts.wallB = _wallCounts.wallC = _wallCounts.wallD = _wallCounts.wallE = 0;
        for (const data of world.windows) {
            const vi  = Math.abs(Math.round(data.x * 7 + data.z * 13)) % 5;
            const key = WALL_VARIANTS[vi];
            temp.position.set(data.x, 0, data.z);
            temp.rotation.set(0, 0, 0); temp.scale.set(1, 1, 1);
            temp.updateMatrix(); show(key, _wallCounts[key]++, temp.matrix);
        }
        WALL_VARIANTS.forEach(k => commit(k, _wallCounts[k]));

        // ── Брёвна и лодки ────────────────────────────────────────────────────
        _logCounts.wooden = _logCounts.boat = 0;
        const logKeyMap = { Wooden: 'wooden', Boat: 'boat' };
        for (let i = 0; i < world.logs.length; i++) {
            const data = world.logs[i];
            const key  = logKeyMap[data.type];
            if (!key) continue;

            const yOffset = data.yOffset || 0;
            const wave    = Math.sin(time * 1.5 + i * 0.7) * 0.04;
            let shakeY = 0, shakeRotX = 0, shakeRotZ = 0;
            if (data.shakeTime) {
                if (data.shakeTime === -1) data.shakeTime = time;
                const age = time - data.shakeTime;
                if (age < 0.55) {
                    const decay = Math.exp(-age * 10), osc = Math.sin(age * 36);
                    shakeY    = osc * decay * 0.10;
                    shakeRotX = osc * decay * 0.15 * (data.shakeDir || 1);
                    shakeRotZ = Math.sin(age * 22) * decay * 0.07;
                } else { data.shakeTime = 0; }
            }
            temp.position.set(data.x, yOffset + wave + shakeY, data.z);
            temp.rotation.set((data.rotX||0) + Math.sin(time*1.5+i*0.7)*0.06 + shakeRotX, 0, (data.rotZ||0) + shakeRotZ);
            temp.scale.set(1, 1, 1.135);
            temp.updateMatrix();
            show(key, _logCounts[key]++, temp.matrix);
            showShadow(key === 'boat' ? 'shadow_boat' : 'shadow_wooden', data.x, data.z, SHADOW_Y_WATER);
        }
        commit('wooden', _logCounts.wooden);
        commit('boat',   _logCounts.boat);

        // ── Кувшинки ──────────────────────────────────────────────────────────
        for (let i = 0; i < world.lilys.length; i++) {
            const data = world.lilys[i];
            const wave = Math.sin(time * 2.0 + i * 1.3) * 0.02;
            const stableRot = Math.abs(Math.sin(data.x * 12.98 + data.z * 78.23) * Math.PI);
            let shakeY = 0, shakeRotX = 0;
            if (data.shakeTime) {
                if (data.shakeTime === -1) data.shakeTime = time;
                const age = time - data.shakeTime;
                if (age < 0.5) {
                    const decay = Math.exp(-age * 12), osc = Math.sin(age * 40);
                    shakeY    = osc * decay * 0.08;
                    shakeRotX = osc * decay * 0.22 * (data.shakeDir || 1);
                } else { data.shakeTime = 0; }
            }
            temp.position.set(data.x, -0.05 + (data.yOffset||0) + wave + shakeY, data.z);
            temp.rotation.set(shakeRotX, stableRot, 0);
            temp.scale.set(1, 1, 1);
            temp.updateMatrix();
            show('lily', i, temp.matrix);
            showShadow('shadow_lilly', data.x, data.z, SHADOW_Y_WATER);
        }
        commit('lily', world.lilys.length);

        // ── Гранаты ───────────────────────────────────────────────────────────
        // Map: rounded z → array of prop x на этом ряду
        const propsByZ = new Map();
        for (const p of world.props) {
            const rz = Math.round(p.z);
            if (!propsByZ.has(rz)) propsByZ.set(rz, []);
            propsByZ.get(rz).push(p.x);
        }
        // t=1 когда граната прямо у пропса по x, t=0 когда дальше shadowRadius
        const SHADOW_RADIUS = 1.5;
        const grenadeShade = (x, z) => {
            const row = propsByZ.get(Math.round(z) - 1);
            if (!row) return 0;
            let minDist = Infinity;
            for (const px of row) minDist = Math.min(minDist, Math.abs(x - (px - 1)));
            return minDist < SHADOW_RADIUS ? 1 - minDist / SHADOW_RADIUS : 0;
        };
        const bGrenade = batches.grenade;
        _grenCounts.HE = _grenCounts.Flash = _grenCounts.Molotov = 0;
        for (const data of world.obstacles) {
            const key = data.type;
            const r   = data.rotation;
            const yFloat = data.hidden ? -1000 : 0.8 + Math.sin(time * 4 + data.phase) * 0.1;
            temp.position.set(data.x, yFloat, data.z);
            temp.rotation.set(r[0], r[1], r[2], 'YXZ');
            temp.rotation.z += data.direction * (data.speed * 0.05);
            temp.scale.set(1, 1, 1);
            temp.updateMatrix();
            const idx = _grenCounts[key]++;
            const entry = pools[`grenade_${key}`];
            show(`grenade_${key}`, idx, temp.matrix);
            if (entry) {
                const t = grenadeShade(data.x, data.z);
                bGrenade.setColorAt(entry.ids[idx], _grenadeColor.lerpColors(_grenadeLight, _grenadeDark, t));
            }
        }
        if (bGrenade.instanceColor) bGrenade.instanceColor.needsUpdate = true;
        commit('grenade_HE', _grenCounts.HE); commit('grenade_Flash', _grenCounts.Flash); commit('grenade_Molotov', _grenCounts.Molotov);

        // ── Waterside (границы вода/суша) ─────────────────────────────────────
        let _watersideCount = 0;
        for (const z of world.waters) {
            for (const [dz, rotY] of [[-1, 0], [1, Math.PI]]) {
                if (!world.waters.has(z + dz)) {
                    const pool = pools['waterside'];
                    if (!pool || _watersideCount >= pool.ids.length) break;
                    temp.position.set(0, 0, z);
                    temp.rotation.set(0, rotY, 0);
                    temp.scale.set(1, 1, 1);
                    temp.updateMatrix();
                    pool.b.setMatrixAt(pool.ids[_watersideCount], temp.matrix);
                    pool.b.setVisibleAt(pool.ids[_watersideCount], true);
                    _watersideCount++;
                }
            }
        }
        commit('waterside', _watersideCount);

        // ── Тени ──────────────────────────────────────────────────────────────
        SHADOW_GEO_KEYS.forEach(k => commit(k, _shadowCounts[k]));

        // ── Dissolve: курица + монеты + медали → uniform ─────────────────────
        const pts = transpPointsUniform.value;
        let _ptIdx = 0;
        const _player = world.playerRef?.current;
        if (_player) { pts[_ptIdx++].set(_player.position.x, _player.position.z, 0.7, 1); }
        for (const c of world.coins) {
            if (!c.collected && _ptIdx < 8) { pts[_ptIdx++].set(c.x, c.z, 0.5, 1); }
        }
        for (const m of world.medals) {
            if (!m.collected && _ptIdx < 8) { pts[_ptIdx++].set(m.x, m.z, 0.5, 1); }
        }
        for (let i = _ptIdx; i < 8; i++) pts[i].w = 0;
    });

    if (!batches) return null;
    return (
        <>
            <primitive object={batches.atlas} />
            <primitive object={batches.main} />
            <primitive object={batches.grenade} />
            <primitive object={batches.shadow} />
        </>
    );
}

useGLTF.preload('/models/obstacle.glb');
useGLTF.preload('/models/wallwindow.glb');
useGLTF.preload('/models/wooden.glb');
useGLTF.preload('/models/boat.glb');
useGLTF.preload('/models/lilly.glb');
useGLTF.preload('/models/grenade.glb');
useGLTF.preload('/models/waterside.glb');
useGLTF.preload('/models/shadow.glb');
