import gsap from "gsap";
import { useLayoutEffect, useMemo, useRef } from "react";
import * as THREE from "three";

const tempObject = new THREE.Object3D();
const colorTop = new THREE.Color("#555555"); // Цвет дыма вверху
const colorMid = new THREE.Color("#ff0000"); // Красный в середине
const colorBase = new THREE.Color("#ffcc00"); // Оранжевый у основания
const colorHot = new THREE.Color("#ffffff"); // Белый в самом эпицентре

export default function VoxelFire({ position }) {
    const count = 80;
    const meshRef = useRef();
    const startTime = useRef(Date.now());

    const material = useMemo(() => new THREE.MeshStandardMaterial({
        emissive: "#ff4400",
        emissiveIntensity: 0.4,
        toneMapped: false
    }), []);

    useLayoutEffect(() => {
        if (!meshRef.current) return;

        gsap.killTweensOf(meshRef.current);

        // 1. Мгновенно скрываем все кубы
        const matrix = new THREE.Matrix4().makeScale(0, 0, 0);
        for (let i = 0; i < count; i++) {
            meshRef.current.setMatrixAt(i, matrix);
        }
        meshRef.current.instanceMatrix.needsUpdate = true;

        startTime.current = Date.now();

        const animateParticle = (i, isGround) => {
            const elapsed = (Date.now() - startTime.current) / 1000;
            if (elapsed > 8) return;

            const angle = Math.random() * Math.PI * 2;
            const radius = Math.random() * 1.8;

            const state = {
                scale: 0,
                x: Math.cos(angle) * radius,
                z: Math.sin(angle) * radius,
                y: isGround ? 0.01 : 0.1,
                tempColor: new THREE.Color() // Временный цвет для расчетов
            };

            const update = () => {
                if (!meshRef.current) return;

                // ВЫЧИСЛЯЕМ ЦВЕТ СТРОГО ПО ВЫСОТЕ
                if (isGround) {
                    // Пятна на земле — яркие, почти белые в центре (colorHot)
                    state.tempColor.copy(colorBase).lerp(colorHot, 0.4);
                } else {
                    // Коэффициент высоты (0 - у земли, 1 - в пике полета)
                    const h = THREE.MathUtils.clamp(state.y / 3.5, 0, 1);

                    if (h < 0.2) {
                        // 0.0 - 0.2: Белый -> Желтый
                        state.tempColor.copy(colorHot).lerp(colorBase, h * 5);
                    } else if (h < 0.5) {
                        // 0.2 - 0.5: Желтый -> Красный
                        state.tempColor.copy(colorBase).lerp(colorMid, (h - 0.2) * 3.33);
                    } else {
                        // 0.5 - 1.0: Красный -> Серый (дым)
                        state.tempColor.copy(colorMid).lerp(colorTop, (h - 0.5) * 2);
                    }
                }

                tempObject.position.set(state.x, state.y, state.z);
                tempObject.scale.setScalar(isGround ? state.scale : state.scale);
                // Для земли можно оставить сплющивание тут же:
                if (isGround) tempObject.scale.y *= 0.15;

                tempObject.updateMatrix();
                meshRef.current.setMatrixAt(i, tempObject.matrix);
                meshRef.current.setColorAt(i, state.tempColor);

                meshRef.current.instanceMatrix.needsUpdate = true;
                if (meshRef.current.instanceColor) meshRef.current.instanceColor.needsUpdate = true;
            };

            const tl = gsap.timeline({ onUpdate: update });

            if (isGround) {
                const lifeTime = 2 + Math.random() * 2;
                tl.to(state, { scale: 0.3 + Math.random() * 0.4, duration: 0.8 });
                tl.to(state, { scale: 0, duration: 1.5, delay: lifeTime });
            } else {
                // ВАЖНО: Убрали tl.to(state.color, ...)!
                const duration = 2.5 + Math.random() * 1.5;
                tl.to(state, { scale: 0.2 + Math.random() * 0.1, duration: 0.5 }, 0);
                tl.to(state, {
                    y: 3 + Math.random() * 1.5,
                    x: state.x + (Math.random() - 0.5) * 1.5,
                    duration: duration,
                    ease: "power1.out"
                }, 0);
                tl.to(state, { scale: 0, duration: 0.8 }, "-=0.8");
            }

            tl.eventCallback("onComplete", () => animateParticle(i, isGround));
        };

        for (let i = 0; i < count; i++) {
            const isGround = i < 35;
            gsap.delayedCall(Math.random() * 2, () => animateParticle(i, isGround));
        }
    }, [position.x, position.z]);

    return (
        <instancedMesh ref={ meshRef } args={ [null, null, count] } position={ position } material={ material }>
            <boxGeometry args={ [0.6, 0.9, 0.6] } />
        </instancedMesh>
    );
}