import { useGameStore } from '../Logic/store';
import ShopModal from './ShopModal';
import ChickenPreview from './ChickenPreview';

export default function WardrobeMenu() {
    const isWardrobeOpen  = useGameStore(s => s.isWardrobeOpen);
    const closeWardrobe   = useGameStore(s => s.closeWardrobe);    // ← назад в меню
    const closeWardrobeAll = useGameStore(s => s.closeWardrobeAll); // ✕ всё закрыть

    if (!isWardrobeOpen) return null;

    return (
        <ShopModal
            title="WARDROBE"
            onBack={closeWardrobe}
            onClose={closeWardrobeAll}
            width="560px"
            height="680px"
        >
            <div style={{ width: '100%', height: '100%', position: 'relative' }}>
                <ChickenPreview />
            </div>
        </ShopModal>
    );
}
