import gsap from "gsap";
import { useLayoutEffect, useRef } from "react";

export default function Explosion({ position }) {
    const groupRef = useRef();
    const count = 20;

    useLayoutEffect(() => {
        if (!groupRef.current) return;

        gsap.killTweensOf(groupRef.current);
        // Анимируем каждый кусочек
        groupRef.current.children.forEach((mesh) => {
            const x = (Math.random() - 0.5) * 4;
            const y = Math.random() * 4;
            const z = (Math.random() - 0.5) * 4;

            // Разлет в стороны
            gsap.to(mesh.position, {
                x, y, z,
                duration: 0.8,
                ease: "power2.out",
            });

            // Вращение
            gsap.to(mesh.rotation, {
                x: Math.random() * Math.PI,
                y: Math.random() * Math.PI,
                duration: 0.8,
            });

            // Исчезновение
            gsap.to(mesh.scale, {
                x: 0, y: 0, z: 0,
                delay: 0.4,
                duration: 0.4,
            });
        });
    }, [position.x, position.z]); // Перезапускаем эффект при изменении позиции

    return (
        <group ref={ groupRef } position={ position }>
            {/* Твои частицы-кубики с emissive материалом */ }
            { Array.from({ length: count }).map((_, i) => (
                <mesh key={ i }>
                    <boxGeometry args={ [0.2, 0.2, 0.2] } />
                    <meshStandardMaterial
                        color={ Math.random() > 0.5 ? "#555555" : "#ff4400" }
                        emissive="#ff2200"
                        emissiveIntensity={ 0.4 }
                    />
                </mesh>
            )) }
        </group>
    );
}