import gsap from "gsap";
import { useLayoutEffect, useRef } from "react";
import { SoundManager } from "./SoundManager";

const DEBRIS_COUNT  = 50;
const SPARK_COUNT   = 30;
const SPREAD        = 7;
const UP            = 6;

export default function ExplosionC4({ position }) {
    const groupRef  = useRef();
    const sparksRef = useRef();
    const flashRef  = useRef();

    useLayoutEffect(() => {
        SoundManager.play('explosion', false);

        // ── Обломки (крупные куски) ────────────────────────────────────────────
        groupRef.current?.children.forEach((mesh) => {
            const angle  = Math.random() * Math.PI * 2;
            const radius = 1.5 + Math.random() * SPREAD;
            const x = Math.cos(angle) * radius;
            const z = Math.sin(angle) * radius;
            const y = 1 + Math.random() * UP;

            gsap.set(mesh.position, { x: 0, y: 0, z: 0 });
            gsap.set(mesh.scale,    { x: 1, y: 1, z: 1 });
            gsap.set(mesh.rotation, { x: 0, y: 0, z: 0 });

            gsap.to(mesh.position, { x, y, z, duration: 0.9, ease: "power3.out" });
            gsap.to(mesh.position, { y: mesh.position.y - 2, duration: 0.5, ease: "power2.in", delay: 0.5 });
            gsap.to(mesh.rotation, {
                x: (Math.random() - 0.5) * Math.PI * 4,
                y: (Math.random() - 0.5) * Math.PI * 4,
                z: (Math.random() - 0.5) * Math.PI * 4,
                duration: 1.0,
            });
            gsap.to(mesh.scale, { x: 0, y: 0, z: 0, delay: 0.5, duration: 0.45 });
        });

        // ── Вспышка ───────────────────────────────────────────────────────────
        if (flashRef.current) {
            gsap.set(flashRef.current.scale, { x: 0.1, y: 0.1, z: 0.1 });
            gsap.to(flashRef.current.scale, { x: 1, y: 1, z: 1, duration: 0.12, ease: "power4.out" });
            gsap.to(flashRef.current.scale, { x: 0, y: 0, z: 0, delay: 0.12, duration: 0.35, ease: "power2.in" });
        }

        // ── Искры (маленькие) ─────────────────────────────────────────────────
        sparksRef.current?.children.forEach((mesh) => {
            const angle  = Math.random() * Math.PI * 2;
            const radius = 0.5 + Math.random() * (SPREAD * 1.3);
            const x = Math.cos(angle) * radius;
            const z = Math.sin(angle) * radius;
            const y = 0.5 + Math.random() * (UP * 1.2);

            gsap.set(mesh.position, { x: 0, y: 0, z: 0 });
            gsap.set(mesh.scale,    { x: 1, y: 1, z: 1 });

            gsap.to(mesh.position, { x, y, z, duration: 0.6, ease: "power4.out" });
            gsap.to(mesh.scale,    { x: 0, y: 0, z: 0, delay: 0.15, duration: 0.45 });
        });

        return () => {
            groupRef.current?.children.forEach(mesh => { gsap.killTweensOf(mesh.position); gsap.killTweensOf(mesh.rotation); gsap.killTweensOf(mesh.scale); });
            sparksRef.current?.children.forEach(mesh => { gsap.killTweensOf(mesh.position); gsap.killTweensOf(mesh.scale); });
            if (flashRef.current) gsap.killTweensOf(flashRef.current.scale);
        };
    }, [position[0], position[2]]);

    return (
        <group position={position}>
            {/* Обломки */}
            <group ref={groupRef}>
                {Array.from({ length: DEBRIS_COUNT }).map((_, i) => {
                    const size = 0.12 + Math.random() * 0.28;
                    const hot  = Math.random() > 0.4;
                    return (
                        <mesh key={i}>
                            <boxGeometry args={[size, size * (0.5 + Math.random()), size]} />
                            <meshStandardMaterial
                                color={hot ? '#ff3300' : '#444444'}
                                emissive={hot ? '#ff1100' : '#220000'}
                                emissiveIntensity={hot ? 0.8 : 0.1}
                            />
                        </mesh>
                    );
                })}
            </group>

            {/* Искры */}
            <group ref={sparksRef}>
                {Array.from({ length: SPARK_COUNT }).map((_, i) => (
                    <mesh key={i}>
                        <sphereGeometry args={[0.05 + Math.random() * 0.07, 4, 4]} />
                        <meshStandardMaterial
                            color="#ffaa00"
                            emissive="#ff6600"
                            emissiveIntensity={1.2}
                        />
                    </mesh>
                ))}
            </group>

            {/* Вспышка-шар */}
            <mesh ref={flashRef}>
                <sphereGeometry args={[1.8, 8, 6]} />
                <meshStandardMaterial
                    color="#ff8800"
                    emissive="#ff4400"
                    emissiveIntensity={2}
                    transparent
                    opacity={0.35}
                    depthWrite={false}
                />
            </mesh>
        </group>
    );
}
