import { useState, useEffect, useRef } from "react";
import { useGameStore } from "./Logic/store";
import { SoundManager } from "./Effects/SoundManager";
import { UPGRADE_MENU_TIMEOUT, UPGRADE_SLOW_DURATION, UPGRADE_INVUL_HITS } from "./Logic/constants";
import MedalReveal from "./MedalReveal";

// ── Утилита форматирования даты ──────────────────────────────────────────────
const formatDate = (ts) => {
    const d = new Date(ts);
    return `${d.getDate().toString().padStart(2,'0')}.${(d.getMonth()+1).toString().padStart(2,'0')}`;
};

// ── Таблица рекордов ─────────────────────────────────────────────────────────
function Leaderboard({ topScores, currentScore, currentDate }) {
    if (!topScores.length) return null;

    return (
        <div style={{
            width: 'min(100%, 300px)',
            marginBottom: '20px',
            border: '1px solid rgba(255,204,0,0.2)',
            borderRadius: '6px',
            overflow: 'hidden',
            maxHeight: 'min(38vh, 260px)',
            display: 'flex',
            flexDirection: 'column',
        }}>
            <div style={{
                padding: '8px 16px',
                background: 'rgba(255,204,0,0.08)',
                fontSize: '10px',
                letterSpacing: '3px',
                color: 'rgba(255,204,0,0.6)',
                fontFamily: 'monospace',
                borderBottom: '1px solid rgba(255,204,0,0.1)',
                flexShrink: 0,
            }}>
                TOP SCORES
            </div>
            <div style={{ overflowY: 'auto', flexGrow: 1 }}>
            {topScores.map((entry, i) => {
                const isThis = entry.score === currentScore && entry.date === currentDate;
                const medal = i === 0 ? '🥇' : i === 1 ? '🥈' : i === 2 ? '🥉' : `${i + 1}.`;

                return (
                    <div key={`${entry.score}-${entry.date}`} style={{
                        display: 'flex',
                        alignItems: 'center',
                        padding: '7px 16px',
                        background: isThis
                            ? 'rgba(255,204,0,0.12)'
                            : i % 2 === 0 ? 'rgba(255,255,255,0.02)' : 'transparent',
                        borderLeft: isThis ? '3px solid #ffcc00' : '3px solid transparent',
                    }}>
                        <span style={{
                            width: '28px',
                            fontSize: i < 3 ? '14px' : '11px',
                            color: i < 3 ? undefined : 'rgba(255,204,0,0.4)',
                            fontFamily: 'monospace',
                        }}>
                            {medal}
                        </span>
                        <span style={{
                            flex: 1,
                            fontSize: '15px',
                            fontWeight: isThis ? '900' : '700',
                            fontFamily: 'monospace',
                            color: isThis ? '#ffcc00' : i === 0 ? '#fff' : 'rgba(255,255,255,0.75)',
                            textShadow: isThis ? '0 0 8px rgba(255,204,0,0.5)' : 'none',
                        }}>
                            {entry.score.toString().padStart(4, '0')}
                        </span>
                        <span style={{
                            fontSize: '10px',
                            color: 'rgba(255,255,255,0.3)',
                            fontFamily: 'monospace',
                        }}>
                            {formatDate(entry.date)}
                        </span>
                    </div>
                );
            })}
            </div>
        </div>
    );
}

// ── Иконка монеты ─────────────────────────────────────────────────────────────
function CoinIcon({ size = '0.7em' }) {
    return (
        <svg width={size} height={size} viewBox="0 0 24 24" style={{ marginBottom: '2px', flexShrink: 0 }}>
            <circle cx="12" cy="12" r="11" fill="#ffd700" stroke="#b8860b" strokeWidth="1.5"/>
            <text x="12" y="17" textAnchor="middle" fontSize="13" fontWeight="bold" fill="#7a5c00" fontFamily="monospace">$</text>
        </svg>
    );
}

// ── Бомба: таймер по центру экрана ───────────────────────────────────────────
function BombHUD() {
    const bombProgress = useGameStore(s => s.bombProgress);
    const progress = bombProgress;
    const secondsLeft = Math.ceil((1 - progress) * 5);
    const isUrgent = progress > 0.6;
    const circumference = 2 * Math.PI * 28;
    const dashOffset = circumference * (1 - progress);

    return (
        <div style={{
            position: 'absolute',
            top: '50%', left: '50%',
            transform: 'translate(-50%, -50%)',
            display: 'flex', flexDirection: 'column',
            alignItems: 'center', gap: '8px',
            pointerEvents: 'none',
            animation: isUrgent ? 'bombShake 0.15s infinite' : 'none',
            zIndex: 100,
        }}>
            <svg width="80" height="80" viewBox="0 0 80 80">
                {/* Фоновое кольцо */}
                <circle cx="40" cy="40" r="28" fill="none"
                    stroke="rgba(255,255,255,0.1)" strokeWidth="5" />
                {/* Прогресс */}
                <circle cx="40" cy="40" r="28" fill="none"
                    stroke={progress > 0.75 ? '#ff2200' : progress > 0.45 ? '#ff8800' : '#ffcc00'}
                    strokeWidth="5"
                    strokeLinecap="round"
                    strokeDasharray={circumference}
                    strokeDashoffset={dashOffset}
                    transform="rotate(-90 40 40)"
                    style={{ transition: 'stroke 0.3s' }}
                />
                {/* Иконка */}
                <text x="40" y="45" textAnchor="middle" fontSize="26" style={{ userSelect: 'none' }}>💣</text>
            </svg>
            <div style={{
                fontSize: 'clamp(16px, 5vw, 22px)',
                fontWeight: '900', fontFamily: 'monospace',
                color: progress > 0.75 ? '#ff2200' : '#ffcc00',
                textShadow: `0 0 12px ${progress > 0.75 ? '#ff0000' : '#ffcc0066'}`,
                letterSpacing: '2px',
            }}>
                {secondsLeft}s
            </div>
        </div>
    );
}

// ── Прицел снайпера — только экранный эффект (сам прицел в 3D) ───────────────
function SniperHUD() {
    const progress = useGameStore(s => s.sniperProgress);
    const alpha = Math.min(1, progress * 1.6);
    return (
        <div style={{ position: 'absolute', inset: 0, pointerEvents: 'none', zIndex: 100, opacity: alpha, transition: 'opacity 0.15s' }}>
            {/* Тёмная маска вокруг прицела */}
            <div style={{
                position: 'absolute', inset: 0,
                background: `radial-gradient(circle at center, transparent ${26 - progress * 8}%, rgba(0,0,0,0.92) ${36 - progress * 6}%)`,
                transition: 'background 0.15s',
            }} />
            {/* Прицел */}
            <svg style={{ position: 'absolute', inset: 0, width: '100%', height: '100%' }} viewBox="0 0 100 100" preserveAspectRatio="xMidYMid meet">
                <line x1="2"  y1="50" x2="50" y2="50" stroke="rgba(0, 0, 0, 0.75)" strokeWidth="0.15" />
                <line x1="50" y1="50" x2="98" y2="50" stroke="rgba(0, 0, 0, 0.75)" strokeWidth="0.15" />
                <line x1="50" y1="2"  x2="50" y2="50" stroke="rgba(0, 0, 0, 0.75)" strokeWidth="0.15" />
                <line x1="50" y1="50" x2="50" y2="98" stroke="rgba(0, 0, 0, 0.75)" strokeWidth="0.15" />
            </svg>
            {progress > 0.3 && (
                <div style={{
                    position: 'absolute', bottom: '18%', left: 0, right: 0,
                    textAlign: 'center', fontSize: '9px', letterSpacing: '3px', fontFamily: 'monospace',
                    color: `rgba(255,60,60,${Math.min(1, (progress - 0.3) * 3)})`,
                    textShadow: '0 0 8px #ff0000',
                }}>
                    MOVE FORWARD
                </div>
            )}
        </div>
    );
}

