import * as THREE from 'three';
import { WATER_ROW_WIDTH, CAUSTICS_Y_OFFSET } from '../Logic/constants';
import { WORLD_POS_VERTEX } from './WaterRowMaterial';

export { CAUSTICS_Y_OFFSET };

// ── Shared geometry (same width as water row, 1 segment — flat) ──────────────
export const causticsGeo = new THREE.PlaneGeometry(WATER_ROW_WIDTH, 1, 1, 1);

// ── Worley caustics (AdditiveBlending) ───────────────────────────────────────
// Техника: два слоя F1-Worley с хроматической дисперсией → min(n1,n2) →
// яркие линии на границах клеток, имитация фокусировки света через рябь.
export const causticsMaterial = new THREE.ShaderMaterial({
    transparent: true,
    depthWrite:  false,
    blending:    THREE.AdditiveBlending,
    side:        THREE.FrontSide,

    uniforms: {
        uTime: { value: 0 },
    },

    vertexShader: WORLD_POS_VERTEX,

    fragmentShader: /* glsl */`
uniform float uTime;
varying vec3  vWorldPos;

// ── Hash → [0,1]² ─────────────────────────────────────────────────────────
vec2 hash22(vec2 p) {
    p = vec2(dot(p, vec2(127.1, 311.7)),
             dot(p, vec2(269.5, 183.3)));
    return fract(sin(p) * 43758.5453);
}

// ── F1 Worley — статичные клетки, движение через сдвиг входа ─────────────
float worley(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    float minD = 1.0;
    for (int x = -1; x <= 1; x++) {
        for (int y = -1; y <= 1; y++) {
            vec2 n  = vec2(float(x), float(y));
            vec2 pt = hash22(i + n);
            float d = length(n + pt - f);
            minD = min(minD, d);
        }
    }
    return minD;
}

void main() {
    vec2 pos = vWorldPos.xz;

    // Слой 1 — крупнее, медленней
    float ns1 = 1.7, t1 = uTime * 0.1, off1 = 0.05;
    vec3 n1 = vec3(
        worley((pos + t1 + vec2( off1,  off1)) * ns1),
        worley((pos + t1 + vec2( off1, -off1)) * ns1),
        worley((pos + t1 + vec2(-off1, -off1)) * ns1)
    );

    // Слой 2 — мельче, быстрей
    float ns2 = 1.2, t2 = uTime * 0.2, off2 = 0.02;
    vec3 n2 = vec3(
        worley((pos + t2 + vec2( off2,  off2)) * ns2),
        worley((pos + t2 + vec2( off2, -off2)) * ns2),
        worley((pos + t2 + vec2(-off2, -off2)) * ns2)
    );

    // min(n1,n2) → яркие там где оба поля одновременно у границы клетки
    vec3 n = min(n1, n2);
    n = pow(n, vec3(2.0)) * 1.8;

    float lum = dot(n, vec3(0.333));
    gl_FragColor = vec4(n, clamp(lum * 1.4, 0.0, 1.0));
}
`,
});

// ── Bottom geometry (subdivided for vertex displacement) ─────────────────────
export const bottomGeo = new THREE.PlaneGeometry(WATER_ROW_WIDTH, 1, 40, 2);

// ── Bottom material — sandy floor with fake refraction via vertex displacement
export const bottomMaterial = new THREE.ShaderMaterial({
    uniforms: {
        uTime: { value: 0 },
    },

    vertexShader: /* glsl */`
uniform float uTime;
varying vec3  vWorldPos;
varying float vDisplace;

void main() {
    vec3 pos   = position;
    vec4 world = modelMatrix * vec4(pos, 1.0);

    float d = sin(world.x * 2.4 + uTime * 0.75) * 0.016
            + sin(world.x * 0.9 - world.z * 1.5 + uTime * 0.55) * 0.012
            + sin(world.z * 3.1 + uTime * 0.95) * 0.008;

    pos.y     += d;
    vDisplace  = d;
    vWorldPos  = world.xyz;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(pos, 1.0);
}
`,

    fragmentShader: /* glsl */`
varying vec3  vWorldPos;
varying float vDisplace;

void main() {
    vec3 sand  = vec3(0.96, 0.86, 0.62);
    vec3 sand2 = vec3(1.00, 0.94, 0.74);
    float p    = sin(vWorldPos.x * 3.1) * sin(vWorldPos.z * 2.7) * 0.5 + 0.5;
    vec3 col   = mix(sand, sand2, p * 0.4);
    col *= clamp(1.0 + vDisplace * 10.0, 0.78, 1.22);
    gl_FragColor = vec4(col, 1.0);
}
`,
});
