import gsap from "gsap";
import { useEffect, useRef } from "react";
import { useWorld } from "../Logic/GameWorldContext";

const POOL_SIZE = 4;   // параллельных облачков
const GRAINS   = 8;    // частиц на один хлопок

export default function DustPuff() {
    const world    = useWorld();
    const poolRefs = useRef([]);
    const poolIdx  = useRef(0);

    useEffect(() => {
        world.emitDustPuff = (x, z) => {
            const idx  = poolIdx.current % POOL_SIZE;
            poolIdx.current = (poolIdx.current + 1) % POOL_SIZE;
            const group = poolRefs.current[idx];
            if (!group) return;

            group.position.set(x, 0, z);

            group.children.forEach((mesh) => {
                const angle = Math.random() * Math.PI * 2;
                const r  = 0.15 + Math.random() * 0.55;
                const tx = Math.cos(angle) * r;
                const tz = Math.sin(angle) * r;
                const ty = 0.05 + Math.random() * 0.25; // низкий взлёт — песок
                const dur = 0.18 + Math.random() * 0.1;

                gsap.killTweensOf(mesh.position);
                gsap.killTweensOf(mesh.scale);
                gsap.killTweensOf(mesh.material);

                gsap.set(mesh.position, { x: 0, y: 0, z: 0 });
                gsap.set(mesh.scale,    { x: 1, y: 1, z: 1 });
                gsap.set(mesh.material, { opacity: 0.65 });

                // Разлетаются вширь, почти без подъёма
                gsap.to(mesh.position, { x: tx, y: ty, z: tz, duration: dur, ease: "power2.out" });
                // Оседают
                gsap.to(mesh.position, { y: 0, duration: 0.2, ease: "power1.in", delay: dur });
                // Уменьшаются и исчезают
                gsap.to(mesh.scale,    { x: 0.1, y: 0.1, z: 0.1, duration: 0.28, delay: dur * 0.5 });
                gsap.to(mesh.material, { opacity: 0, duration: 0.22, delay: dur * 0.6 });
            });
        };

        return () => { world.emitDustPuff = null; };
    }, []); // eslint-disable-line

    return (
        <>
            {Array.from({ length: POOL_SIZE }).map((_, pi) => (
                <group key={pi} ref={el => { poolRefs.current[pi] = el; }}>
                    {Array.from({ length: GRAINS }).map((_, di) => (
                        <mesh key={di}>
                            <boxGeometry args={[0.08, 0.05, 0.08]} />
                            <meshStandardMaterial
                                color="#c8a870"
                                transparent
                                opacity={0}
                                roughness={1}
                                metalness={0}
                                depthWrite={false}
                            />
                        </mesh>
                    ))}
                </group>
            ))}
        </>
    );
}
