import { useEffect, useMemo } from "react";
import { PhysicsManager } from "../Logic/PhysicsEngine";

export default function AnubisProp({ z, x, type = 'column1' }) {
    // Генерируем уникальный ID для этого конкретного пропса
    const id = useMemo(() => `prop-${z}-${x}-${type}`, [z, x, type]);

    useEffect(() => {
        const data = { id, z, x, type };
        
        // 1. Регистрируем в PhysicsEngine (для коллизий и для рендера)
        PhysicsManager.register('prop', data);

        // 2. При удалении ряда (размонтировании) — убираем из системы
        return () => PhysicsManager.remove('prop', id);
    }, [id, z, x, type]);

    return null; 
}