// onBack  — стрелочка ← : закрывает только это окно, возвращает в пауза-меню
// onClose — крестик  ✕ : закрывает всё включая паузу
export default function ShopModal({ title, onBack, onClose, children, width = '560px', height = '640px' }) {
    return (
        <div style={{
            position: 'fixed', inset: 0, zIndex: 3500,
            // Такое же затемнение как у паузы — rgba(0,0,0,0.6) + blur
            // Пауза-меню под ним полностью скрыто, фон одинаковый
            background: 'rgba(0,0,0,0.82)',
            backdropFilter: 'blur(12px)',
            WebkitBackdropFilter: 'blur(12px)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontFamily: 'monospace',
            animation: 'shopFadeIn 0.2s ease-out',
        }}>
            <div style={{
                width: `min(${width}, 95vw)`,
                height: `min(${height}, 92vh)`,
                background: 'rgba(8,8,8,0.96)',
                border: '1px solid rgba(255,204,0,0.18)',
                borderRadius: '10px',
                display: 'flex', flexDirection: 'column',
                overflow: 'hidden',
                boxShadow: '0 32px 80px rgba(0,0,0,0.8)',
            }}>
                {/* Header */}
                <div style={{
                    display: 'flex', alignItems: 'center',
                    padding: '13px 16px',
                    borderBottom: '1px solid rgba(255,204,0,0.1)',
                    flexShrink: 0, gap: '10px',
                }}>
                    {/* ← Назад в пауза-меню */}
                    <button onPointerDown={onBack} style={{
                        background: 'none',
                        border: '1px solid rgba(255,204,0,0.2)',
                        color: '#ffcc00', fontSize: '16px',
                        width: '30px', height: '30px',
                        cursor: 'pointer', borderRadius: '4px',
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        WebkitTapHighlightColor: 'transparent',
                        flexShrink: 0,
                        lineHeight: 1,
                    }}>←</button>

                    {/* Заголовок по центру */}
                    <div style={{
                        flex: 1, textAlign: 'center',
                        fontSize: '10px', letterSpacing: '4px',
                        color: 'rgba(255,204,0,0.6)',
                    }}>
                        {title}
                    </div>

                    {/* ✕ Закрыть всё */}
                    <button onPointerDown={onClose} style={{
                        background: 'none',
                        border: '1px solid rgba(255,100,100,0.25)',
                        color: 'rgba(255,120,120,0.8)', fontSize: '13px',
                        width: '30px', height: '30px',
                        cursor: 'pointer', borderRadius: '4px',
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        WebkitTapHighlightColor: 'transparent',
                        flexShrink: 0,
                    }}>✕</button>
                </div>

                {/* Content */}
                <div style={{ flex: 1, overflow: 'hidden', minHeight: 0 }}>
                    {children}
                </div>
            </div>

            <style>{`
                @keyframes shopFadeIn {
                    from { opacity: 0; transform: scale(0.96); }
                    to   { opacity: 1; transform: scale(1); }
                }
            `}</style>
        </div>
    );
}
