import * as THREE from 'three';

// ── Dissolve uniform (shared between atlas + anubis materials) ────────────────
const _transpPts = [];
for (let i = 0; i < 8; i++) _transpPts.push(new THREE.Vector4(0, 0, 1.5, 0));
export const transpPointsUniform = { value: _transpPts };

// ── Shared toon material (vertex colours, used by all non-tile geometry) ──────
export const sharedAnubisMaterial = new THREE.MeshStandardMaterial({
    vertexColors: true,
    flatShading:  false,
    roughness:    0.82,
    metalness:    0.0,
});

sharedAnubisMaterial.color.set('#ffe8cc');

// ── Shadow material (shadow.png — запечённая тень под пропсами) ───────────────
const _shadowTexture = new THREE.TextureLoader().load('/images/shadow.png');
_shadowTexture.colorSpace = THREE.SRGBColorSpace;
_shadowTexture.flipY      = false;

export const sharedShadowMaterial = new THREE.MeshBasicMaterial({
    map:          _shadowTexture,
    transparent:  true,
    depthWrite:   false,
    alphaTest:    0.05,
    opacity:      0.45,
    stencilWrite: true,
    stencilFunc:  THREE.EqualStencilFunc,
    stencilRef:   0,
    stencilFail:  THREE.KeepStencilOp,
    stencilZFail: THREE.KeepStencilOp,
    stencilZPass: THREE.IncrementWrapStencilOp,
});

// ── Atlas material (tile.glb — UV-mapped to textureAtlas.png) ─────────────────
const _loader = new THREE.TextureLoader();
const _atlasTexture = _loader.load('/images/textureAtlas.png');
_atlasTexture.colorSpace = THREE.SRGBColorSpace;
_atlasTexture.flipY      = false;
_atlasTexture.minFilter  = THREE.LinearMipmapLinearFilter;
_atlasTexture.magFilter  = THREE.LinearFilter;

export const sharedAtlasMaterial = new THREE.MeshStandardMaterial({
    map:          _atlasTexture,
    vertexColors: false,
    flatShading:  false,
    roughness:    0.82,
    metalness:    0.0,
});

sharedAtlasMaterial.onBeforeCompile = (shader) => {
    shader.uniforms.uTranspPoints = transpPointsUniform;

    // ── Vertex: vWorldPos ────────────────────────────────────────────────────
    shader.vertexShader = shader.vertexShader.replace(
        'void main() {',
        `varying vec3 vWorldPos;\nvoid main() {`
    );
    shader.vertexShader = shader.vertexShader.replace(
        '#include <fog_vertex>',
        `#include <fog_vertex>
        #ifdef USE_BATCHING
            vWorldPos = (modelMatrix * batchingMatrix * vec4(transformed, 1.0)).xyz;
        #else
            vWorldPos = (modelMatrix * vec4(transformed, 1.0)).xyz;
        #endif`
    );

    // ── Fragment: dissolve near coins/medals ─────────────────────────────────
    shader.fragmentShader = shader.fragmentShader.replace(
        'void main() {',
        `varying vec3 vWorldPos;\nuniform vec4 uTranspPoints[8];\nvoid main() {`
    );
    shader.fragmentShader = shader.fragmentShader.replace(
        '#include <dithering_fragment>',
        `#include <dithering_fragment>
        vec3 _camFwdA = normalize(vec3(viewMatrix[0][2], viewMatrix[1][2], viewMatrix[2][2]));
        float _dissolveA = 0.0;
        for (int i = 0; i < 8; i++) {
            if (uTranspPoints[i].w < 0.5) continue;
            vec3 _coinWA = vec3(uTranspPoints[i].x, 0.5, uTranspPoints[i].y);
            vec3 _offA = vWorldPos - _coinWA;
            float _alongA = dot(_offA, _camFwdA);
            if (_alongA > 0.0) {
                float _perpA = length(_offA - _alongA * _camFwdA);
                _dissolveA = max(_dissolveA, 1.0 - smoothstep(0.0, uTranspPoints[i].z, _perpA));
            }
        }
        if (_dissolveA > 0.01) {
            vec2 _bPosA = mod(floor(gl_FragCoord.xy), 4.0);
            float _bxA = _bPosA.x, _byA = _bPosA.y;
            float _bayerA;
            if      (_bxA < 1.0) _bayerA = (_byA < 1.0 ? 0.0  : _byA < 2.0 ? 12.0 : _byA < 3.0 ? 3.0  : 15.0);
            else if (_bxA < 2.0) _bayerA = (_byA < 1.0 ? 8.0  : _byA < 2.0 ? 4.0  : _byA < 3.0 ? 11.0 : 7.0 );
            else if (_bxA < 3.0) _bayerA = (_byA < 1.0 ? 2.0  : _byA < 2.0 ? 14.0 : _byA < 3.0 ? 1.0  : 13.0);
            else                 _bayerA = (_byA < 1.0 ? 10.0 : _byA < 2.0 ? 6.0  : _byA < 3.0 ? 9.0  : 5.0 );
            if (_bayerA / 16.0 < _dissolveA * 0.88) discard;
        }`
    );
};

sharedAtlasMaterial.customProgramCacheKey = () => 'atlas_dissolve_v4';

// ── Grenade material (metallic + specular highlight) ──────────────────────────
export const sharedGrenadeMaterial = new THREE.MeshStandardMaterial({
    vertexColors: true,
    roughness:    0.42,
    metalness:    0.0,
});

// ── Chicken material (vertex colours × atlas B&W texture = multiply) ──────────
export const sharedChickenMaterial = new THREE.MeshStandardMaterial({
    map:          _atlasTexture,
    vertexColors: true,
    flatShading:  false,
    roughness:    0.82,
    metalness:    0.0,
});

sharedAnubisMaterial.onBeforeCompile = (shader) => {
    shader.uniforms.uTranspPoints = transpPointsUniform;

    // ── Vertex shader: vWorldPos + vWorldNormal ──────────────────────────────
    shader.vertexShader = shader.vertexShader.replace(
        'void main() {',
        `varying vec3 vWorldPos;\nvarying vec3 vWorldNormal;\nvoid main() {`
    );
    shader.vertexShader = shader.vertexShader.replace(
        '#include <fog_vertex>',
        `#include <fog_vertex>
        #ifdef USE_BATCHING
            vWorldPos    = (modelMatrix * batchingMatrix * vec4(transformed, 1.0)).xyz;
            vWorldNormal = normalize(mat3(modelMatrix) * mat3(batchingMatrix) * objectNormal);
        #else
            vWorldPos    = (modelMatrix * vec4(transformed, 1.0)).xyz;
            vWorldNormal = normalize(mat3(modelMatrix) * objectNormal);
        #endif`
    );

    // ── Fragment shader ──────────────────────────────────────────────────────
    shader.fragmentShader = shader.fragmentShader.replace(
        'void main() {',
        `varying vec3 vWorldPos;\nvarying vec3 vWorldNormal;\nuniform vec4 uTranspPoints[8];\nvoid main() {`
    );
    shader.fragmentShader = shader.fragmentShader.replace(
        '#include <dithering_fragment>',
        `
        // ── Toon shading (half-lambert + smooth step) ──
        vec3  _sunDir = normalize(vec3(8.0, 12.0, -8.0));
        float _NdotL  = dot(vWorldNormal, _sunDir) * 0.5 + 0.5;
        float _toon   = smoothstep(0.38, 0.62, _NdotL);
        gl_FragColor.rgb *= mix(0.72, 1.18, _toon);

        // ── Height gradient (светлый верх → тёмный низ) ──
        float _hGrad = smoothstep(-0.5, 3.5, vWorldPos.y);
        gl_FragColor.rgb *= mix(0.88, 1.12, _hGrad);

        // ── Rim light (camera-based Fresnel) ──
        vec3  _viewDir = normalize(cameraPosition - vWorldPos);
        float _rim     = 1.0 - max(dot(vWorldNormal, _viewDir), 0.0);
        _rim = pow(_rim, 3.0);
        gl_FragColor.rgb += _rim * 0.08;

        // ── Saturation boost ──
        float _gray = dot(gl_FragColor.rgb, vec3(0.333));
        gl_FragColor.rgb = mix(vec3(_gray), gl_FragColor.rgb, 1.25);

        // ── Bayer dithering ──
        #include <dithering_fragment>
        vec2 _bPos = mod(floor(gl_FragCoord.xy), 4.0);
        float _bx = _bPos.x, _by = _bPos.y;
        float _bayer;
        if      (_bx < 1.0) _bayer = (_by < 1.0 ? 0.0  : _by < 2.0 ? 12.0 : _by < 3.0 ? 3.0  : 15.0);
        else if (_bx < 2.0) _bayer = (_by < 1.0 ? 8.0  : _by < 2.0 ? 4.0  : _by < 3.0 ? 11.0 : 7.0 );
        else if (_bx < 3.0) _bayer = (_by < 1.0 ? 2.0  : _by < 2.0 ? 14.0 : _by < 3.0 ? 1.0  : 13.0);
        else                _bayer = (_by < 1.0 ? 10.0 : _by < 2.0 ? 6.0  : _by < 3.0 ? 9.0  : 5.0 );
        gl_FragColor.rgb += (_bayer / 16.0 - 0.5) * 0.032;

        // ── Dissolve: ortho parallel rays from coin toward camera ──
        vec3 _camFwd = normalize(vec3(viewMatrix[0][2], viewMatrix[1][2], viewMatrix[2][2]));
        float _dissolve = 0.0;
        for (int i = 0; i < 8; i++) {
            if (uTranspPoints[i].w < 0.5) continue;
            vec3 _coinW = vec3(uTranspPoints[i].x, 0.5, uTranspPoints[i].y);
            vec3 _off = vWorldPos - _coinW;
            float _along = dot(_off, _camFwd);
            if (_along > 0.0) {
                float _perp = length(_off - _along * _camFwd);
                _dissolve = max(_dissolve, 1.0 - smoothstep(0.0, uTranspPoints[i].z, _perp));
            }
        }
        if (_dissolve > 0.01 && _bayer / 16.0 < _dissolve * 0.88) discard;`
    );
};

sharedAnubisMaterial.customProgramCacheKey = () => 'anubis_toon_v8';
