import { useEffect, useMemo } from "react";
import { PhysicsManager } from "../Logic/PhysicsEngine";

export default function LilyPad({ z, x }) {
    const id = useMemo(() => Math.random().toString(36), []);

    useEffect(() => {
        const data = { id, z, x };
        PhysicsManager.register('lily', data);
        return () => PhysicsManager.remove('lily', id);
    }, [id, z, x]);

    return null; // Рисует LilyPadView
}